// --- Service Identification ---

#[derive(Debug, Clone)]
pub struct ServiceId {
    pub monitor_id: String,
    pub hub_id: String,
    pub service_type: String,
}

// --- Service Management ---

struct ServiceManager {
    service_id: ServiceId,
}

impl ServiceManager {
    fn new(service_id: ServiceId) -> Self {
        Self { service_id }
    }

    fn restart_sweep_service(&self) -> io::Result<()> {
        // Kill existing sweep service
        let _ = std::process::Command::new("pkill")
            .arg("-f")
            .arg(format!("sweep-service.*{}", self.service_id.hub_id))
            .status();

        // Give it time to shut down
        std::thread::sleep(std::time::Duration::from_millis(1000));

        // Start new sweep service
        let _ = std::process::Command::new("./target/release/sweep-service")
            .env("AEON_MONITOR_ID", &self.service_id.monitor_id)
            .env("AEON_HUB_ID", &self.service_id.hub_id)
            .spawn()?;

        // Give it time to start
        std::thread::sleep(std::time::Duration::from_millis(2000));

        Ok(())
    }

    fn restart_chaos_service(&self) -> io::Result<()> {
        // Kill existing chaos service
        let _ = std::process::Command::new("pkill")
            .arg("-f")
            .arg(format!("chaos-service.*{}", self.service_id.hub_id))
            .status();

        // Give it time to shut down
        std::thread::sleep(std::time::Duration::from_millis(1000));

        // Start new chaos service
        let _ = std::process::Command::new("./target/release/chaos-service")
            .env("AEON_MONITOR_ID", &self.service_id.monitor_id)
            .env("AEON_HUB_ID", &self.service_id.hub_id)
            .spawn()?;

        // Give it time to start
        std::thread::sleep(std::time::Duration::from_millis(2000));

        Ok(())
    }

    fn restart_all_services(&self) -> io::Result<()> {
        self.restart_chaos_service()?;
        self.restart_sweep_service()?;
        Ok(())
    }

    fn check_service_status(&self) -> (bool, bool) {
        let sweep_socket = self.service_id.sweep_socket_path();
        let chaos_socket = self.service_id.chaos_socket_path();

        let sweep_running = std::path::Path::new(&sweep_socket).exists();
        let chaos_running = std::path::Path::new(&chaos_socket).exists();

        (sweep_running, chaos_running)
    }
}

impl ServiceId {
    fn new(monitor_id: &str, hub_id: &str, service_type: &str) -> Self {
        Self {
            monitor_id: monitor_id.to_string(),
            hub_id: hub_id.to_string(),
            service_type: service_type.to_string(),
        }
    }

    fn sweep_socket_path(&self) -> String {
        format!(
            "/tmp/sweep-service-{}-{}.sock",
            self.monitor_id, self.hub_id
        )
    }

    fn chaos_socket_path(&self) -> String {
        format!(
            "/tmp/chaos-service-{}-{}.sock",
            self.monitor_id, self.hub_id
        )
    }

    fn from_env() -> Self {
        let monitor_id = env::var("AEON_MONITOR_ID").unwrap_or_else(|_| "default".to_string());
        let hub_id = env::var("AEON_HUB_ID").unwrap_or_else(|_| "hub-0".to_string());
        Self::new(&monitor_id, &hub_id, "monitor")
    }
}

// --- IPC Protocol for Sweep Service Communication ---

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum IpcMessage {
    Frame(PleromaticFrame),
    SweepRequest,
    SweepResult(SweepResult),
    Ping,
    Pong,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SweepResult {
    pub timestamp_ms: u64,
    pub coverage_percentage: f32,
    pub active_bins: usize,
    pub total_energy: f32,
    pub sweep_duration_ms: u64,
    pub frequency_peaks: Vec<FrequencyPeak>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct FrequencyPeak {
    pub bin_index: usize,
    pub center_hz: u64,
    pub magnitude: f32,
    pub bandwidth_hz: u64,
}

// --- IPC Client for Sweep Service ---

struct SweepServiceClient {
    service_id: ServiceId,
}

impl SweepServiceClient {
    fn new(service_id: ServiceId) -> Self {
        Self { service_id }
    }

    fn send_frame(&self, frame: &PleromaticFrame) -> io::Result<()> {
        let socket_path = self.service_id.sweep_socket_path();
        if let Ok(mut stream) = UnixStream::connect(&socket_path) {
            let message = IpcMessage::Frame(frame.clone());
            let data = bincode::serialize(&message).unwrap();
            let len = (data.len() as u32).to_le_bytes();

            stream.write_all(&len)?;
            stream.write_all(&data)?;
        }
        Ok(())
    }

    fn request_sweep(&self) -> io::Result<Option<SweepResult>> {
        let socket_path = self.service_id.sweep_socket_path();
        if let Ok(mut stream) = UnixStream::connect(&socket_path) {
            let message = IpcMessage::SweepRequest;
            let data = bincode::serialize(&message).unwrap();
            let len = (data.len() as u32).to_le_bytes();

            stream.write_all(&len)?;
            stream.write_all(&data)?;

            // Read response length
            let mut len_bytes = [0u8; 4];
            if stream.read_exact(&mut len_bytes).is_err() {
                return Ok(None);
            }

            let response_len = u32::from_le_bytes(len_bytes) as usize;
            if response_len > 1_000_000 {
                return Ok(None);
            }

            // Read response
            let mut response_data = vec![0u8; response_len];
            if stream.read_exact(&mut response_data).is_err() {
                return Ok(None);
            }

            // Deserialize response
            let response: IpcMessage = bincode::deserialize(&response_data).unwrap();

            match response {
                IpcMessage::SweepResult(result) => Ok(Some(result)),
                _ => Ok(None),
            }
        } else {
            Ok(None)
        }
    }
}

// --- GNOSTIC ATLAS: INTERESTING MANIFOLDS ---
const GNOSTIC_ATLAS: &[(&str, &str)] = &[
    ("PAGERS-A", "152480000"),
    ("IOT-JUNGLE", "915000000"),
    ("ISM-BAND", "433920000"),
    ("NOAA-19-APT", "137100000"),
    ("NOAA-15-APT", "137620000"),
    ("NOAA-18-APT", "137912500"),
    ("FIRE-DISPATCH", "154370000"),
    ("ISS-SPACE-GROUND", "145800000"),
    ("FM-BROADCAST", "101100000"),
    ("PIRATE-RADIO", "6925000"),
    ("AUTOMOTIVE", "315000000"),
];

/// A resolved RF event detected in the manifold.
struct ResolvedEvent {
    pub freq_hz: u64,
    pub magnitude: f32,
    pub classification: String,
}

fn pick_random_resonance() -> (usize, &'static str, &'static str) {
    let idx = (std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_micros() as usize)
        % GNOSTIC_ATLAS.len();
    (idx, GNOSTIC_ATLAS[idx].0, GNOSTIC_ATLAS[idx].1)
}

fn is_noaa_apt_atlas_idx(idx: usize) -> bool {
    GNOSTIC_ATLAS
        .get(idx % GNOSTIC_ATLAS.len())
        .map(|(name, _)| name.contains("NOAA") && name.contains("APT"))
        .unwrap_or(false)
}

fn next_noaa_apt_atlas_idx(current_idx: usize) -> Option<usize> {
    for step in 1..=GNOSTIC_ATLAS.len() {
        let idx = (current_idx + step) % GNOSTIC_ATLAS.len();
        if is_noaa_apt_atlas_idx(idx) {
            return Some(idx);
        }
    }
    None
}

/// Smart Bridge Guard — handles background hardware capture.
struct SdrBridgeGuard {
    child: Option<std::process::Child>,
    pub freq_name: String,
    pub freq_hz: String,
    pub atlas_idx: Option<usize>,
}

impl SdrBridgeGuard {
    fn new(freq_hz_opt: Option<String>, atlas_idx: Option<usize>) -> Self {
        let (idx, name, hz) = if let Some(hz) = freq_hz_opt {
            (None, "MANUAL".to_string(), hz)
        } else if let Some(i) = atlas_idx {
            let entry = GNOSTIC_ATLAS[i % GNOSTIC_ATLAS.len()];
            (
                Some(i % GNOSTIC_ATLAS.len()),
                entry.0.to_string(),
                entry.1.to_string(),
            )
        } else {
            let (i, n, h) = pick_random_resonance();
            (Some(i), n.to_string(), h.to_string())
        };

        // If --oneoff is present in args, we bypass bridge initialization entirely.
        if std::env::args().any(|a| a == "--oneoff") {
            return Self {
                child: None,
                freq_name: name,
                freq_hz: hz,
                atlas_idx: idx,
            };
        }

        // Kill any existing orphans to release the hardware lock
        let _ = std::process::Command::new("pkill")
            .arg("-9")
            .arg("-f")
            .arg("rtl_sdr")
            .status();
        let _ = std::process::Command::new("pkill")
            .arg("-9")
            .arg("-f")
            .arg("iq-waterfall-frame")
            .status();
        let _ = std::process::Command::new("pkill")
            .arg("-9")
            .arg("-f")
            .arg("rtl_fm")
            .status();
        let _ = std::process::Command::new("pkill")
            .arg("-9")
            .arg("-f")
            .arg("noaa-apt-audio-frame")
            .status();

        // Hardware cooldown: give the USB bus more time to stabilize
        std::thread::sleep(std::time::Duration::from_millis(5000));

        // Only attempt if rtl_sdr is in the PATH
        if std::process::Command::new("rtl_sdr")
            .arg("-h")
            .stdout(std::process::Stdio::null())
            .stderr(std::process::Stdio::null())
            .status()
            .is_err()
        {
            return Self {
                child: None,
                freq_name: name,
                freq_hz: hz,
                atlas_idx: idx,
            };
        }

        let bridge_log = "sdr_bridge.log";

        // AEON GATEWAY: rtl_433 is only useful for ISM/IoT style sensors.
        // Pagers need an FM audio demodulator plus a POCSAG/FLEX decoder.
        let is_pager = name.starts_with("PAGERS");
        let is_noaa_apt = name.contains("NOAA") && name.contains("APT");
        let is_digital = name == "IOT-JUNGLE" || name == "ISM-BAND" || name == "AUTOMOTIVE";
        let bin_path = "./target/release/iq-waterfall-frame";
        if !is_noaa_apt && !is_pager && !is_digital && !std::path::Path::new(bin_path).exists() {
            let _ = std::fs::OpenOptions::new()
                .append(true)
                .create(true)
                .open(bridge_log)
                .and_then(|mut f| writeln!(f, "[AEON-BRIDGE] missing {}", bin_path));
            return Self {
                child: None,
                freq_name: name,
                freq_hz: hz,
                atlas_idx: idx,
            };
        }
        let cmd = if is_noaa_apt {
            format!("./scripts/aeon_noaa_apt_resolver.sh {}", hz)
        } else if is_pager {
            if std::path::Path::new("./target/release/pager-resolver").exists() {
                format!("./target/release/pager-resolver {}", hz)
            } else {
                format!("./scripts/aeon_pager_resolver.sh {}", hz)
            }
        } else if is_digital {
            format!("./scripts/aeon_iot_snatcher.sh {}", hz)
        } else {
            format!(
                "retry_count=0; max_retries=8; success_count=0; adaptive_gain=30; while [ $retry_count -lt $max_retries ]; do echo \"[$(date)] Starting rtl_sdr (attempt $((retry_count + 1))/$max_retries, gain=$adaptive_gain)...\" >> {}; rtl_sdr -f {} -s 256000 -g $adaptive_gain - 2>> {} | {} --input - --output spectrum_waterfall.frame --iq-rate 256000 --center-hz {} --fft-size 512 --rows 48 --source-id auto_bridge --continuous; exit_code=$?; echo \"[$(date)] rtl_sdr exited with code $exit_code\" >> {}; if [ $exit_code -eq 0 ]; then retry_count=0; success_count=$((success_count + 1)); if [ $success_count -gt 3 ]; then echo \"[$(date)] Stable connection achieved, monitoring...\" >> {}; success_count=3; adaptive_gain=30; else adaptive_gain=$((adaptive_gain + 5)); if [ $adaptive_gain -gt 40 ]; then adaptive_gain=20; fi; fi; sleep 1; else retry_count=$((retry_count + 1)); success_count=0; adaptive_gain=$((adaptive_gain + 10)); if [ $adaptive_gain -gt 40 ]; then adaptive_gain=25; fi; echo \"[$(date)] Failed, adjusting gain to $adaptive_gain, retry in 20s...\" >> {}; sleep 20; fi; done",
                bridge_log, hz, bridge_log, bin_path, hz, bridge_log, bridge_log, bridge_log
            )
        };

        let child = std::process::Command::new("sh")
            .arg("-c")
            .arg(cmd)
            .spawn()
            .ok();
        let _ = std::fs::OpenOptions::new()
            .append(true)
            .create(true)
            .open(bridge_log)
            .and_then(|mut f| {
                writeln!(
                    f,
                    "[AEON-BRIDGE] spawned {} {} child={}",
                    name,
                    hz,
                    child.is_some()
                )
            });

        Self {
            child,
            freq_name: name,
            freq_hz: hz,
            atlas_idx: idx,
        }
    }
}

impl Drop for SdrBridgeGuard {
    fn drop(&mut self) {
        if let Some(mut c) = self.child.take() {
            let _ = c.kill();
        }
        let _ = std::process::Command::new("pkill")
            .arg("-9")
            .arg("-f")
            .arg("rtl_sdr")
            .status();
        let _ = std::process::Command::new("pkill")
            .arg("-9")
            .arg("-f")
            .arg("iq-waterfall-frame")
            .status();
        let _ = std::process::Command::new("pkill")
            .arg("-9")
            .arg("-f")
            .arg("rtl_fm")
            .status();
        let _ = std::process::Command::new("pkill")
            .arg("-9")
            .arg("-f")
            .arg("noaa-apt-audio-frame")
            .status();
    }
}

// --- AEON DESIGN SYSTEM: COLORS & ARTIFACTS ---
const AEON_RESET: &str = "\x1b[0m";
const AEON_BOLD: &str = "\x1b[1m";
const AEON_DIM: &str = "\x1b[2m";
const AEON_GREEN: &str = "\x1b[38;5;46m";
const AEON_CYAN: &str = "\x1b[38;5;51m";
const AEON_AMBER: &str = "\x1b[38;5;214m";
const AEON_BLUE: &str = "\x1b[38;5;27m";
const AEON_GHOST: &str = "\x1b[38;5;240m";

struct TextPanel {
    width: usize,
    lines: Vec<String>,
}

fn overlay_text_panel(
    mut rendered: String,
    panel: &TextPanel,
    _screen_width: usize,
    row: usize,
    col: usize,
) -> String {
    rendered.push_str("\x1b7");
    for (idx, line) in panel.lines.iter().enumerate() {
        rendered.push_str(&format!(
            "\x1b[{};{}H{}{}{}",
            row + idx + 1,
            col + 1,
            AEON_AMBER,
            line,
            AEON_RESET
        ));
    }
    rendered.push_str("\x1b8");
    rendered
}

fn pad_visible(input: &str, width: usize) -> String {
    let mut out: String = input.chars().take(width).collect();
    let len = out.chars().count();
    if len < width {
        out.push_str(&" ".repeat(width - len));
    }
    out
}

fn draw_box_header(title: &str, cols: usize, color: &str) -> String {
    let mut out = String::new();
    let title_len = title.len();
    let padding = if cols > title_len + 4 {
        (cols - title_len - 4) / 2
    } else {
        0
    };

    // GNOSTIC SHIMMER: PHI-modulated temporal pulse at 12 BPM (0.2 Hz)
    let time_now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_secs_f64();
    const PHI: f64 = 1.618034;
    let shimmer = (time_now * 0.2 * PHI).sin() * 0.5 + 0.5;
    let is_cyan = color.contains("51");
    let dynamic_color = if shimmer > 0.7 && is_cyan {
        AEON_GHOST
    } else {
        color
    };

    out.push_str(dynamic_color);
    out.push_str(&"━".repeat(padding));
    out.push_str("┫ ");
    out.push_str(AEON_BOLD);
    out.push_str(title);
    out.push_str(AEON_RESET);
    out.push_str(dynamic_color);
    out.push_str(" ┣");
    let remaining = cols.saturating_sub(padding + title_len + 4);
    out.push_str(&"━".repeat(remaining));
    out.push_str(AEON_RESET);
    out.push('\n');
    out
}

fn draw_box_footer(cols: usize, color: &str) -> String {
    format!("{}{}{}\n", color, "━".repeat(cols), AEON_RESET)
}

#[cfg(unix)]
fn tty_dimensions() -> (usize, usize) {
    use libc::{ioctl, winsize, STDOUT_FILENO, TIOCGWINSZ};
    use std::mem::MaybeUninit;
    let mut ws = MaybeUninit::<winsize>::uninit();
    unsafe {
        if ioctl(STDOUT_FILENO, TIOCGWINSZ, ws.as_mut_ptr()) == 0 {
            let ws = ws.assume_init();
            let cols = ws.ws_col as usize;
            let rows = ws.ws_row as usize;
            if cols >= 20 && rows >= 5 {
                return (cols, rows);
            }
        }
    }
    tty_dimensions_from_env()
}

#[cfg(not(unix))]
fn tty_dimensions() -> (usize, usize) {
    tty_dimensions_from_env()
}

fn tty_dimensions_from_env() -> (usize, usize) {
    let cols = std::env::var("COLUMNS")
        .ok()
        .and_then(|s| s.parse().ok())
        .unwrap_or(96);
    let rows = std::env::var("LINES")
        .ok()
        .and_then(|s| s.parse().ok())
        .unwrap_or(40);
    (cols.max(40), rows.max(12))
}

fn clamp_line_visual_width(line: &str, cols: usize) -> String {
    if cols == 0 {
        return String::new();
    }
    let mut out = String::new();
    let mut w = 0usize;
    let mut in_escape = false;
    for ch in line.chars() {
        if ch == '\x1b' {
            in_escape = true;
        }

        if in_escape {
            out.push(ch);
            // Escape sequence terminates on an alphabetic character
            if ch.is_ascii_alphabetic() {
                in_escape = false;
            }
            continue;
        }

        let cw = if ch == '\t' { 4 } else { 1 };
        if w + cw > cols {
            break;
        }
        out.push(ch);
        w += cw;
    }
    out
}

fn clamp_frame_to_terminal(text: &str, max_lines: usize, cols: usize) -> String {
    text.lines()
        .take(max_lines)
        .map(|ln| clamp_line_visual_width(ln, cols))
        .collect::<Vec<_>>()
        .join("\n")
}

/// Restore cursor / alternate screen on panic or normal exit (Unix fullscreen pattern).
struct TerminalPresentationGuard {
    alt_screen: bool,
}

impl TerminalPresentationGuard {
    fn enter(alt_screen: bool) -> Self {
        if alt_screen {
            print!("\x1b[?1049h");
        }
        print!("\x1b[?25l");
        let _ = io::stdout().flush();
        Self { alt_screen }
    }
}

impl Drop for TerminalPresentationGuard {
    fn drop(&mut self) {
        print!("\x1b[?25h");
        if self.alt_screen {
            print!("\x1b[?1049l");
        }
        let _ = io::stdout().flush();
    }
}

