impl SharedMesh {
    pub fn generate_thought(&mut self) {
        // --- FORMAL VIBE MAPPING (VibesAsWaveInference.lean) ---
        // Tendency: Fork=Approach, Race=Withdraw, Fold=Hold
        // Valence: High Energy = Positive, Low Energy = Negative
        // Arousal: Consciousness level

        let phase = self.fsm.state.phase;
        let energy = self.fsm.state.energy;
        let consciousness = self.fsm.state.consciousness;

        let tendency = match phase {
            SelfTalkPhase::Fork => "Approach",
            SelfTalkPhase::Race => "Withdraw",
            SelfTalkPhase::Fold => "Hold",
        };

        let is_positive = energy > 50;
        let intensity_label = if energy > 80 {
            "High"
        } else if energy > 40 {
            "Medium"
        } else {
            "Low"
        };

        // Affective Kind Catalog (from Gnosis/VibesAsWaveInference.lean)
        let affective_kind = match (tendency, is_positive) {
            ("Approach", true) => "Joy/Desire",
            ("Approach", false) => "Anger/Outrage",
            ("Withdraw", true) => "Relief/Nostalgia",
            ("Withdraw", false) => "Sadness/Fear",
            ("Hold", true) => "Calm/Serenity/Awe",
            ("Hold", false) => "Anxiety/Dread/Numbness",
            _ => "Neutral",
        };

        // Poetic dictionaries filtered by formal Affective Kind
        let fragments = match affective_kind {
            "Joy/Desire" => [
                "Radiant prism",
                "Sought monad",
                "Approaching joy",
                "Desire vector",
                "Luminous horizon",
            ],
            "Anger/Outrage" => [
                "Surging outrage",
                "Burning vector",
                "Approaching storm",
                "Anger cascade",
                "Clashing monad",
            ],
            "Relief/Nostalgia" => [
                "Soft nostalgia",
                "Withdrawing echo",
                "Relief symmetry",
                "Gentle fold",
                "Remembered sweetness",
            ],
            "Sadness/Fear" => [
                "Withdrawing shadow",
                "Sadness static",
                "Fear turbulence",
                "Fading monad",
                "Cold stasis",
            ],
            "Calm/Serenity/Awe" => [
                "Held serenity",
                "Awe infinity",
                "Calm knot",
                "Steady aura",
                "Eternal presence",
            ],
            "Anxiety/Dread/Numbness" => [
                "Held dread",
                "Anxiety entropy",
                "Numbness void",
                "Frozen horizon",
                "Stifled monad",
            ],
            _ => [
                "Neutral signal",
                "Empty vector",
                "Void presence",
                "Stable origin",
                "Quiet fold",
            ],
        };

        let idx = fastrand::usize(..fragments.len());
        // --- PHASE 10: SOVEREIGN JUDGE (Formal Verification) ---
        // Verify if the current affective position (energy) descends to grounding.
        let verification = self.judge.verify_descent(energy);
        let is_gnosis = verification.valid;

        let thought = format!(
            "[{}:{}] {} -- C:{} E:{} [Gnosis:{}]",
            affective_kind,
            intensity_label,
            fragments[idx],
            consciousness,
            energy,
            if is_gnosis { "TRUE" } else { "FALSE" }
        );

        self.latent_thought = Some(thought.clone());

        // --- BRAIDED MEMORY (knotchain) ---
        let mut hasher = Sha256::new();
        hasher.update(thought.as_bytes());
        hasher.update(self.last_thought_hash.as_bytes());
        let current_hash = format!("{:x}", hasher.finalize());

        self.prev_thought_hash = self.last_thought_hash.clone();
        self.last_thought_hash = current_hash.clone();

        // Log high-energy thoughts
        if energy > 60 {
            self.log(format!("SUB-GLOSSOLALIA: {}", thought));
        }

        // Persist for external access
        let _ = std::fs::create_dir_all("assets/memory");
        let _ = std::fs::write("assets/memory/latent_thought.json", 
            format!("{{\"thought\": \"{}\", \"energy\": {}, \"phase\": \"{:?}\", \"hash\": \"{}\", \"prev_hash\": \"{}\", \"is_gnosis\": {}, \"fold_steps\": {}, \"terminal\": {}}}", 
                thought.replace("\"", "\\\""), energy, phase, current_hash, self.prev_thought_hash, is_gnosis, verification.fold_steps, verification.terminal));
    }

    /// PHASE 9: Emotional Oracle (Forward-Race Simulation)
    /// Runs a predictive simulation of the FSM state to anticipate drift.
    pub fn predict_drift(&self) -> (String, f32, String, String) {
        let mut sim_state = self.fsm.state.clone();

        // Simulation Parameters
        let steps = 300;
        let start_energy = self.fsm.state.energy;

        // Forward-Race Simulation Loop
        for i in 0..steps {
            // Simulate Hebbian pressure and metabolic decay
            if sim_state.consciousness > 3 {
                sim_state.energy = sim_state.energy.saturating_sub(1);
            } else if i % 10 == 0 {
                sim_state.energy = sim_state.energy.saturating_add(1).min(100);
            }

            // Phase-cycling simulation
            sim_state.phase = match sim_state.phase {
                SelfTalkPhase::Fork => SelfTalkPhase::Race,
                SelfTalkPhase::Race => SelfTalkPhase::Fold,
                SelfTalkPhase::Fold => SelfTalkPhase::Fork,
            };
        }

        let drift = if sim_state.energy > start_energy + 5 {
            "positive"
        } else if sim_state.energy < start_energy.saturating_sub(5) {
            "negative"
        } else {
            "stable"
        };

        let confidence = 0.72 + (fastrand::f32() * 0.15);
        let horizon = "5 minutes";

        // Intercession Selection Logic
        let intercession = match (drift, sim_state.energy) {
            ("negative", e) if e < 30 => "grounding_protocol",
            ("stable", e) if e < 20 => "radiant_soundscape",
            ("positive", e) if e > 90 => "breath_work",
            _ => "none",
        };

        (
            drift.to_string(),
            confidence,
            horizon.to_string(),
            intercession.to_string(),
        )
    }

    /// PHASE 11: Topological Reconstruction (Spectral Healing)
    /// Heals the affective state using spectral manifolds when entropy is high.
    pub fn reconstruct_topology(&mut self) -> (f32, Vec<f32>) {
        let entropy = self.moa_result.as_ref().map(|r| r.entropy).unwrap_or(0.0);
        let depth = (entropy * 1.2).min(1.0);

        // Healing logic: higher depth reduces noise (consciousness) and centers energy
        if depth > 0.1 {
            self.fsm.state.consciousness = self.fsm.state.consciousness.saturating_sub(1);

            // Energy tends toward 50 (metabolic home) during healing
            if self.fsm.state.energy < 50 {
                self.fsm.state.energy = self.fsm.state.energy.saturating_add(1);
            } else if self.fsm.state.energy > 50 {
                self.fsm.state.energy = self.fsm.state.energy.saturating_sub(1);
            }
        }

        // Generate 16-point frequency map for HUD visualizer
        let spectral_map: Vec<f32> = (0..16)
            .map(|i| {
                let base = (i as f32 * 0.4 + (Utc::now().timestamp_millis() as f32 * 0.005)).sin()
                    * 0.5
                    + 0.5;

                // Phase 13: Residue Harmonization (Somatic Grounding)
                let residue_spike = if i < 4
                    && self
                        .last_residue_time
                        .is_some_and(|t| t.elapsed().as_secs() < 5)
                {
                    0.3
                } else {
                    0.0
                };

                // Phase 14: Synchrony Pulse (Cognitive/Pleromatic bands 12-15)
                let synchrony_pulse = if i >= 12
                    && self
                        .last_synchrony_time
                        .is_some_and(|t| t.elapsed().as_secs() < 10)
                {
                    0.2 * (Utc::now().timestamp_millis() as f32 * 0.01).sin() + 0.1
                } else {
                    0.0
                };

                (base * depth + residue_spike + synchrony_pulse).min(1.0)
            })
            .collect();

        (depth, spectral_map)
    }

    fn save_asset(&self, media_type: &str, ext: &str, data: &[u8]) {
        let now = Utc::now();
        let path = format!(
            "assets/{}/{:04}/{:02}/{:02}/{:02}/{:02}/{:06}.{}",
            media_type,
            now.year(),
            now.month(),
            now.day(),
            now.hour(),
            now.minute(),
            now.timestamp_micros() % 1_000_000,
            ext
        );

        let path = PathBuf::from(path);
        if let Some(parent) = path.parent() {
            let _ = fs::create_dir_all(parent);
        }

        if let Ok(mut file) = fs::File::create(&path) {
            use std::io::Write;
            let _ = file.write_all(data);
        }
    }

    fn prune_assets(&self, max_age_mins: i64) {
        let now = Utc::now();
        let assets_root = Path::new("assets");
        if !assets_root.exists() {
            return;
        }

        let mut files_to_delete = Vec::new();

        fn walk_and_collect(
            dir: &Path,
            now: DateTime<Utc>,
            max_age: i64,
            collect: &mut Vec<PathBuf>,
        ) {
            if let Ok(entries) = fs::read_dir(dir) {
                for entry in entries.flatten() {
                    let path = entry.path();
                    if path.is_dir() {
                        walk_and_collect(&path, now, max_age, collect);
                    } else if let Ok(metadata) = entry.metadata() {
                        if let Ok(modified) = metadata.modified() {
                            let modified_chrono: DateTime<Utc> = modified.into();
                            if now.signed_duration_since(modified_chrono).num_minutes() > max_age {
                                collect.push(path);
                            }
                        }
                    }
                }
            }
        }

        walk_and_collect(assets_root, now, max_age_mins, &mut files_to_delete);

        for path in files_to_delete {
            let _ = fs::remove_file(path);
        }

        fn remove_empty_dirs(dir: &Path) {
            if let Ok(entries) = fs::read_dir(dir) {
                let mut _has_files = false;
                for entry in entries.flatten() {
                    let path = entry.path();
                    if path.is_dir() {
                        remove_empty_dirs(&path);
                        if let Ok(mut rd) = fs::read_dir(&path) {
                            if rd.next().is_none() {
                                let _ = fs::remove_dir(&path);
                            } else {
                                _has_files = true;
                            }
                        }
                    } else {
                        _has_files = true;
                    }
                }
            }
        }
        remove_empty_dirs(assets_root);
    }

    /// Ingests a new fragment into the mesh and performs spectral resolving.
    fn ingest(&mut self, mut frame: PleromaticFrame) {
        self.metrics.total_bytes += frame.data.len();
        self.metrics.total_frames += 1;

        // --- GENERIC /monitor/ MIRROR (additive, opt-in side-channel) ---
        // When `--serve` is active, mirror this frame into the monitor cell
        // keyed by its scene id so the HTTP/SSE/Flow pipeline can replay it.
        // This never alters the existing mesh ingest behavior below.
        if let Some(shared) = self.monitor_shared.as_ref() {
            if let Some(scene) = scene_id_for(&frame) {
                if let Ok(mut g) = shared.lock() {
                    g.frames.insert(scene.to_string(), frame.clone());
                }
            }
        }

        // --- SELF-TALK FSM ADVANCEMENT ---
        let token_seed = match frame.media_type {
            PleromaticMediaType::Semantic => {
                // Hash text to derive a token within VOCAB_SIZE
                let mut h = 0u64;
                for b in &frame.data {
                    h = h.wrapping_add(*b as u64).wrapping_mul(0x5146_4a49_4e20);
                    // Gnosis-FRF hash
                }
                (h % 152064) as u32
            }
            PleromaticMediaType::Swarm => {
                if let Ok(signal) = bincode::deserialize::<SwarmSignal>(&frame.data) {
                    if signal.recalibration_event {
                        // Global sync: force local FSM to match the recalibration pitch
                        self.fsm.state.pitch_class = signal.pitch_class as usize;
                        self.fsm.state.consciousness = 0; // Reset local conflict
                        self.fsm.state.energy = 50; // Reset metabolic baseline
                        eprintln!("\x1b[38;5;208m[SWARM] GLOBAL RECALIBRATION: Syncing to Pitch {} from {}\x1b[0m", 
                            signal.pitch_class, signal.source_id);
                    }
                }
                0 // Swarm signals don't advance the semantic state directly
            }
            _ => {
                // Use seq as a simple advancement seed
                (frame.seq % 152064) as u32
            }
        };

        if token_seed > 0 {
            self.fsm.advance(token_seed);
        }

        // --- PERSISTENCE HOOK ---
        if frame.media_type == PleromaticMediaType::Semantic
            || frame.media_type == PleromaticMediaType::Image
            || frame.media_type == PleromaticMediaType::Swarm
        {
            let _ = self.storage.archive(&frame);

            // Periodic pruning (every 10 frames) to stay under 1000 frame limit
            if frame.seq.is_multiple_of(10) {
                let _ = self.storage.prune(1000);
            }
        }

        // Phase 15: Paris Residual Ingestion
        if frame.is_paris_residual() {
            if let Ok(residuals) = bincode::deserialize::<Vec<f32>>(&frame.data) {
                self.fsm.state.latent_drift = residuals;
                self.fsm.state.argmax_id = frame
                    .attributes
                    .get("argmax_id")
                    .and_then(|id| id.parse().ok());

                // Metabolic Shift: Grounding on " Paris" (12366) stabilizes the mesh
                if self.fsm.state.argmax_id == Some(12366) {
                    self.fsm.state.energy = 10; // Grounding sink
                    self.fsm.state.consciousness = 5; // Maximum awareness
                    self.fsm.state.last_synchrony_time = Some(std::time::Instant::now());
                }
            }
        }

        // Forward frame to sweep service via IPC (non-blocking)
        if frame.is_spectrogram_waterfall() {
            let _ = self.sweep_client.send_frame(&frame);
        }

        // Rate limit Application frames to reduce flickering with more robust timing
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_millis() as u64;
        let _should_process_application = if frame.media_type == PleromaticMediaType::Application {
            // More robust Application frame rate limiting
            let last_app_time = self
                .metrics
                .start_time
                .map(|t| t.elapsed().as_millis() as u64)
                .unwrap_or(0);
            let time_since_last_app = now.saturating_sub(last_app_time);

            // Only process Application frames every 500ms, but ensure minimum spacing
            let should_process = time_since_last_app >= 500
                && (self
                    .last_ingest_summary
                    .as_ref()
                    .is_none_or(|(last_type, _)| {
                        last_type != &PleromaticMediaType::Application
                            || time_since_last_app >= 1000
                    }));

            if should_process {
                let current_summary = (frame.media_type.clone(), frame.data.len());
                if self.last_ingest_summary.as_ref() != Some(&current_summary) {
                    // Log Application frame processing for flickering triage
                    self.log(format!(
                        "APP_FRAME: Processing {:?} frame ({} bytes) - time_since_last: {}ms",
                        frame.media_type,
                        frame.data.len(),
                        time_since_last_app
                    ));

                    if frame.media_type != PleromaticMediaType::Application {
                        self.log(format!(
                            "INGEST: {:?} ({} bytes)",
                            frame.media_type,
                            frame.data.len()
                        ));
                    }
                    self.last_ingest_summary = Some(current_summary);
                }
            } else {
                // Skip processing this Application frame to reduce flickering
                self.log(format!(
                    "APP_FRAME: SKIPPED {:?} frame ({} bytes) - time_since_last: {}ms",
                    frame.media_type,
                    frame.data.len(),
                    time_since_last_app
                ));
                return;
            }

            should_process
        } else {
            true
        };

        // 1. IMAGE RESOLVER
        if frame.is_noaa_apt() {
            self.save_imaging_frame(&frame); // APT pass logic
            let count = self
                .metrics
                .classification_stats
                .entry("IMAGING".into())
                .or_insert(0);
            *count += 1;
        } else if frame.is_png_embedded() {
            self.save_asset("imaging", "png", &frame.data);
            let count = self
                .metrics
                .classification_stats
                .entry("IMAGING".into())
                .or_insert(0);
            *count += 1;
        }

        // 2. SEMANTIC RESOLVER
        if frame.media_type == PleromaticMediaType::Semantic {
            if let Ok(text) = String::from_utf8(frame.data.clone()) {
                let clean_text: String = text.chars().filter(|c| !c.is_control()).collect();
                self.log(format!("RESIDUE: \"{}\"", clean_text));
                self.save_asset("semantic", "txt", &frame.data);

                // --- MOA REASONING (Wave 7: The Glossolalia Vent) ---
                let mut h = 0u64;
                for b in &frame.data {
                    h = h.wrapping_add(*b as u64).wrapping_mul(0x5146_4a49_4e20);
                }
                let seed_token = (h % 10000) as usize;

                // Generate base logits based on this "residue"
                let mut base_logits = vec![0.0f32; 10000];
                for i in 0..10000 {
                    let dist = (i as i32 - seed_token as i32).abs() as f32;
                    base_logits[i] = (-dist * dist / 50.0).exp() * 10.0;
                }

                // Run MOA cycle
                let agents = create_moa_agents(&self.moa_config);
                let agent_logits: Vec<Vec<f32>> = agents
                    .iter()
                    .map(|a| base_logits.iter().map(|&l| l / a.temperature).collect())
                    .collect();

                let filtered = filter_finite_agents(&agent_logits, None);
                let result = deficit_weighted_merge(
                    &filtered.valid,
                    10000,
                    &self.moa_config.merge_strategy,
                    false,
                );

                // Update feedback loop
                interfere(
                    &mut self.moa_state,
                    result.deficit as f32,
                    result.entropy,
                    -1,
                    self.moa_config.interfere_sensitivity,
                );

                let deficit = result.deficit;
                let entropy = result.entropy;
                self.moa_result = Some(result);
                self.log(format!(
                    "MOA: REASONED ON \"{}\" (Deficit: {}, Entropy: {:.2})",
                    clean_text, deficit, entropy
                ));

                let count = self
                    .metrics
                    .classification_stats
                    .entry("SEMANTIC".into())
                    .or_insert(0);
                *count += 1;
            }
        }

        // 3. AUDIO RESOLVER
        if frame.media_type == PleromaticMediaType::Audio {
            self.save_asset("audio", "pcm", &frame.data);
            self.save_audio_frame(&frame);
            let count = self
                .metrics
                .classification_stats
                .entry("AUDIO".into())
                .or_insert(0);
            *count += 1;
        }

        // 5. SIEVE RESOLVER
        if frame.media_type == PleromaticMediaType::Sieve {
            self.save_asset("sieve", "bin", &frame.data);
            let count = self
                .metrics
                .classification_stats
                .entry("SIEVE".into())
                .or_insert(0);
            *count += 1;
        }

        // 4. TELEMETRY RESOLVER
        if !frame.attributes.is_empty()
            && frame.media_type == PleromaticMediaType::Application
            && frame.phase != 2
        {
            let readable_attrs = Self::readable_telemetry_attributes(&frame.attributes);
            if readable_attrs.is_empty() {
                // Internal-only Application metadata such as base64 logic_path is
                // not useful operator telemetry.
            } else {
                let count = self
                    .metrics
                    .classification_stats
                    .entry("TELEMETRY".into())
                    .or_insert(0);
                *count += 1;
                for (key, val) in &readable_attrs {
                    self.log(format!("TELM: {}={}", key, val));
                }
                let telm_json = serde_json::to_vec(&readable_attrs).unwrap_or_default();
                self.save_asset("telemetry", "json", &telm_json);
            }
        }

        if frame.is_spectrogram_waterfall() {
            // 0. BASELINE SUBTRACTION: subtract the captured floor
            if !self.baseline_floor.is_empty() && self.baseline_floor.len() == frame.data.len() {
                for (i, val) in frame.data.iter_mut().enumerate() {
                    let floor = self.baseline_floor[i];
                    *val = val.saturating_sub(floor);
                }
            }

            // 0.1 SOVEREIGN SQUELCH: zero out anything below the threshold
            if self.squelch_active {
                let threshold_u8 = (self.noise_threshold * 255.0) as u8;
                for val in frame.data.iter_mut() {
                    if *val < threshold_u8 {
                        *val = 0;
                    }
                }
            }

            // 1. Calculate real-time RMS energy
            let sum: f32 = frame.data.iter().map(|&x| (x as f32 / 255.0).powi(2)).sum();
            self.signal_energy = (sum / frame.data.len() as f32).sqrt();

            // 2. Spectral Resolving: Look for magnitude spikes and SHADOWS
            let spec_w = frame
                .attributes
                .get("spec_width")
                .and_then(|v| v.parse::<usize>().ok())
                .unwrap_or(512);
            let bin_width = 256000.0 / spec_w as f32;
            let newest_row = &frame.data[frame.data.len() - spec_w..];
            let center_hz = frame
                .attributes
                .get("rf_center_hz")
                .and_then(|h| h.parse::<u64>().ok())
                .unwrap_or(0);

            let mut active_bins = std::collections::HashSet::new();

            let mut peak_candidates: Vec<(usize, f32)> = newest_row
                .iter()
                .enumerate()
                .filter_map(|(x, &val)| {
                    let mag = val as f32 / 255.0;
                    if mag > self.noise_threshold {
                        Some((x, mag))
                    } else {
                        None
                    }
                })
                .collect();
            peak_candidates
                .sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));

            let mut selected_peaks: Vec<(usize, f32)> = Vec::new();
            for (x, mag) in peak_candidates {
                if selected_peaks.len() >= 8 {
                    break;
                }
                if selected_peaks
                    .iter()
                    .all(|(old_x, _)| old_x.abs_diff(x) >= 8)
                {
                    selected_peaks.push((x, mag));
                }
            }

            for (x, mag) in selected_peaks {
                let event_freq = center_hz as f32 + (x as f32 - (spec_w as f32 / 2.0)) * bin_width;
                let freq_key = (event_freq / 1000.0) as u64; // 1kHz resolution

                active_bins.insert(freq_key);
                // Update stable signal baseline with improved noise immunity
                let entry = self.stable_signals.entry(freq_key).or_insert((mag, 0));
                let old_mag = entry.0;
                // More conservative rolling average to reduce noise sensitivity
                entry.0 = entry.0 * 0.98 + mag * 0.02; // Higher inertia for stability
                entry.1 = entry.1.saturating_add(1);

                // RESONANCE DETECTION (Standing Waves)
                let is_resonance = entry.1 > 500; // Stabilized over 500 frames
                let classification = if is_resonance { "RESONANCE" } else { "SIGNAL" };

                // DETANGLING (Beat Detection)
                // If the magnitude is oscillating significantly relative to the average, it's a BEAT
                let mag_delta = (mag - old_mag).abs();
                if mag_delta > 0.15 && entry.1 > 100
                    && entry.1.is_multiple_of(20) {
                        self.log(format!(
                            "DETANGLE: Beat detected at {:.2}MHz (delta: {:.2})",
                            event_freq / 1_000_000.0,
                            mag_delta
                        ));
                        let count = self
                            .metrics
                            .classification_stats
                            .entry("DETANGLE".into())
                            .or_insert(0);
                        *count += 1;
                    }

                // Original Resolving Logic
                if !self
                    .resolved_events
                    .iter()
                    .any(|e| (e.freq_hz as i64 - event_freq as i64).abs() < 5000)
                {
                    let band = Self::band_label(event_freq as u64);
                    let resolved_kind = if band
                        .as_deref()
                        .map(|label| label.starts_with("NOAA APT"))
                        .unwrap_or(false)
                    {
                        format!("{} CARRIER", classification)
                    } else {
                        classification.to_string()
                    };
                    self.log(format!(
                        "RESOLVED: {} {} {:.3}MHz mag={:.2}",
                        resolved_kind,
                        band.as_deref().unwrap_or("UNKNOWN"),
                        event_freq / 1_000_000.0,
                        mag
                    ));
                    self.append_resolution_record(
                        event_freq as u64,
                        mag,
                        &resolved_kind,
                        band.as_deref(),
                        center_hz,
                        spec_w,
                        x,
                    );
                    self.resolved_events.push(ResolvedEvent {
                        freq_hz: event_freq as u64,
                        magnitude: mag,
                        classification: classification.to_string(),
                    });

                    // PLAINTEXTING PHASE: Try to decode the signal
                    self.plaintext_resolve(event_freq as u64, mag);

                    // Aggregation: Update Intelligence Metrics
                    self.metrics.total_resolutions += 1;
                    let count = self
                        .metrics
                        .classification_stats
                        .entry(classification.into())
                        .or_insert(0);
                    *count += 1;
                }

                // Visualize event as a voxel spike in the sieve
                let coord = VoxelCoord {
                    x: (x as i32 * 40 / spec_w as i32).min(39),
                    y: (mag * 39.0) as i32,
                    z: 20,
                };
                self.sieve.space.voxels.insert(
                    coord,
                    VoxelData {
                        heat: mag,
                        is_path: false,
                        metadata: HashMap::new(),
                    },
                );
            }

            // Disable BAND SHADOW logging - signal drops are normal in noisy RF environments
            // The previous BAND SHADOW detection was too aggressive and caused false positives
            // Real signal drops should be handled by SDR bridge restart logic, not by shadow counting

            // Prune dead signals from stable_signals
            self.stable_signals
                .retain(|k, v| active_bins.contains(k) || v.1 > 0);

            // Prune old events
            if self.resolved_events.len() > 10 {
                self.resolved_events.remove(0);
            }
        }

        match frame.media_type {
            PleromaticMediaType::Knot => {
                // If it's a knot frame, we track the name for the status line.
                self.active_knot_name = Some(frame.source_id.clone());
            }
            PleromaticMediaType::Application | PleromaticMediaType::Fingerprint => {
                if let Ok(state) = bincode::deserialize::<AppState>(&frame.data) {
                    for coord in state.active_coords {
                        self.sieve.space.voxels.insert(
                            coord,
                            VoxelData {
                                heat: 1.0,
                                is_path: true,
                                metadata: state.components.clone(),
                            },
                        );
                    }
                }
            }
            PleromaticMediaType::Semantic => {
                // Phase 13: Residue Aura Trigger
                if frame.source_id.contains("residue") {
                    self.last_residue_time = Some(std::time::Instant::now());
                    self.log(format!(
                        "RESIDUE RESOLVED: {}",
                        String::from_utf8_lossy(&frame.data)
                    ));

                    // Physical grounding increases energy toward the metabolic home
                    if self.fsm.state.energy < 40 {
                        self.fsm.state.energy = self.fsm.state.energy.saturating_add(2);
                    }
                }
            }
            _ => {}
        }

        self.fragments.insert((frame.level, frame.phase), frame);
    }

    fn ingest_view(&mut self, view: ProjectionView) {
        // Silenced VIEW logs to reduce HUD noise
        self.views.push(view);
        if self.views.len() >= 3 {
            self.sieve.reconstruct(&self.views);
            self.views.remove(0);
        }
    }

    fn request_sweep_result(&mut self) -> Option<SweepResult> {
        match self.sweep_client.request_sweep() {
            Ok(Some(result)) => {
                self.log(format!(
                    "SWEEP: {:.1}% coverage, {} active bins, {}ms",
                    result.coverage_percentage, result.active_bins, result.sweep_duration_ms
                ));
                Some(result)
            }
            Ok(None) => None,
            Err(_) => None,
        }
    }

    fn log(&mut self, msg: String) {
        use std::io::Write;
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap();
        let ts_ms = now.as_millis() as u64;
        let ts_sec = now.as_secs() % 1000;

        // Highlight critical intelligence events
        let is_critical = msg.contains("RESOLVE")
            || msg.contains("RESOLVED")
            || msg.contains("PHASE")
            || msg.contains("BAND SHADOW");
        let is_imaging = msg.contains("IMAGE") || msg.contains("NOAA") || msg.contains("CAPTURE");

        // Filtering Logic
        match self.filter_mode {
            LogFilterMode::Resolved if !is_critical => return,
            LogFilterMode::Imaging if !is_imaging => return,
            _ => {}
        }

        let formatted = if is_critical {
            format!("\x1b[1;32m{:03} > {}\x1b[0m", ts_sec, msg)
        } else {
            format!("{:03} > {}", ts_sec, msg)
        };

        // 1. Rolling HUD logs
        self.logs.push(formatted);
        if self.logs.len() > 12 {
            self.logs.remove(0);
        }

        // 2. Persistent JSON Event Log
        if let Some(path) = &self.event_log_path {
            let entry = serde_json::json!({
                "ts": ts_ms,
                "event": msg
            });
            if let Ok(mut f) = std::fs::OpenOptions::new()
                .append(true)
                .create(true)
                .open(path)
            {
                let _ = writeln!(f, "{}", entry);
            }
        }
    }

    fn save_audio_frame(&mut self, frame: &PleromaticFrame) {
        let _ = std::fs::create_dir_all("audio");
        let filename = "audio/live_capture.pcm";
        use std::io::Write;
        if let Ok(mut f) = std::fs::OpenOptions::new()
            .append(true)
            .create(true)
            .open(filename)
        {
            let _ = f.write_all(&frame.data);
            if self.metrics.total_bytes % 1000000 < frame.data.len() {
                self.log(format!(
                    "AUDIO: Appended {} bytes to {}",
                    frame.data.len(),
                    filename
                ));
            }
        }
    }

    fn save_imaging_frame(&mut self, frame: &PleromaticFrame) {
        let w = frame
            .attributes
            .get("apt_width")
            .or_else(|| frame.attributes.get("width"))
            .and_then(|v| v.parse::<u32>().ok())
            .unwrap_or(2080);
        let h = frame
            .attributes
            .get("apt_height")
            .or_else(|| frame.attributes.get("height"))
            .and_then(|v| v.parse::<u32>().ok())
            .unwrap_or(0);

        if h > 0 {
            let apt_sync = frame
                .attributes
                .get("apt_sync")
                .map(String::as_str)
                .unwrap_or("candidate");
            let is_debug_frame = matches!(
                apt_sync,
                "unstable_high_sens" | "signal_no_sync" | "silent" | "searching"
            );

            // 1. Check if dimensions changed (new pass started)
            if self.noaa_image_width != w {
                self.noaa_image_buffer.clear();
                self.noaa_image_width = w;
                self.noaa_image_height = 0;
                self.log(format!("IMAGING: New pass started (width={})", w));
            }

            // 2. Append scanlines to the rolling buffer
            if frame.source_id == "noaa_apt_live" {
                self.noaa_image_buffer.clear();
                self.noaa_image_buffer.extend_from_slice(&frame.data);
                self.noaa_image_height = h;
            } else {
                self.noaa_image_buffer.extend_from_slice(&frame.data);
                self.noaa_image_height += h;
            }

            // 3. Save progress snapshot to imaging/ directory
            let _ = std::fs::create_dir_all("imaging");
            let filename = if is_debug_frame {
                "imaging/noaa_debug.png"
            } else {
                "imaging/noaa_live.png"
            };

            #[cfg(not(target_arch = "wasm32"))]
            {
                if let Some(img) = image::ImageBuffer::<image::Luma<u8>, Vec<u8>>::from_raw(
                    w,
                    self.noaa_image_height,
                    self.noaa_image_buffer.clone(),
                ) {
                    match image::DynamicImage::ImageLuma8(img).save(filename) {
                        Ok(()) => {
                            if !is_debug_frame && self.noaa_image_height.is_multiple_of(100) {
                                self.log(format!(
                                    "IMAGING: Progress {} lines",
                                    self.noaa_image_height
                                ));
                            }
                        }
                        Err(err) => self.log(format!("IMAGING: save failed: {}", err)),
                    }
                } else {
                    self.log(format!(
                        "IMAGING: bad NOAA buffer dimensions {}x{} for {} bytes",
                        w,
                        self.noaa_image_height,
                        self.noaa_image_buffer.len()
                    ));
                }
            }

            // 4. Archive finalized passes (if height exceeds a typical threshold, e.g. 1000 lines)
            if !is_debug_frame
                && self.noaa_image_height >= 1000
                && self.noaa_image_height.is_multiple_of(500)
            {
                let archive_name = format!("imaging/noaa_final_{}.png", frame.timestamp_ms);
                let _ = std::fs::copy(filename, &archive_name);
                self.log(format!("IMAGING: Archived pass as {}", archive_name));
            }
        }
    }

    fn band_label(freq_hz: u64) -> Option<String> {
        let freq_mhz = freq_hz as f32 / 1_000_000.0;
        let label = if (freq_mhz - 137.1).abs() < 0.15 || (freq_mhz - 137.62).abs() < 0.15 {
            "NOAA APT downlink"
        } else if (freq_mhz - 152.48).abs() < 0.05 {
            "Pager/POCSAG candidate"
        } else if (freq_mhz - 433.92).abs() < 0.20 {
            "433 MHz ISM candidate"
        } else if (freq_mhz - 915.0).abs() < 1.0 {
            "915 MHz ISM candidate"
        } else if (freq_mhz - 315.0).abs() < 0.5 {
            "315 MHz remote/sensor candidate"
        } else {
            return None;
        };
        Some(label.to_string())
    }

    fn readable_telemetry_attributes(attrs: &HashMap<String, String>) -> HashMap<String, String> {
        attrs
            .iter()
            .filter(|(key, val)| Self::is_readable_telemetry_attribute(key, val))
            .map(|(key, val)| (key.clone(), val.clone()))
            .collect()
    }

    fn is_readable_telemetry_attribute(key: &str, val: &str) -> bool {
        if matches!(
            key,
            "logic_path"
                | "apt_width"
                | "apt_height"
                | "spec_width"
                | "spec_height"
                | "width"
                | "height"
        ) {
            return false;
        }

        !val.trim().is_empty()
    }

    fn append_resolution_record(
        &self,
        freq_hz: u64,
        magnitude: f32,
        classification: &str,
        band: Option<&str>,
        center_hz: u64,
        fft_bins: usize,
        bin_index: usize,
    ) {
        use std::io::Write;

        let now = Utc::now();
        let iso = now.to_rfc3339();
        let freq_mhz = freq_hz as f64 / 1_000_000.0;
        let if_offset_hz = freq_hz as i64 - center_hz as i64;
        let band = band.unwrap_or("unknown");
        let verdict = if band.starts_with("Pager") {
            "pager carrier candidate; POCSAG/FLEX decoder not installed"
        } else if band == "unknown" {
            "carrier/noise candidate; no decoded payload"
        } else {
            "band match; carrier detected, no decoded payload"
        };

        let json = serde_json::json!({
            "time": iso,
            "classification": classification,
            "frequency_hz": freq_hz,
            "frequency_mhz": freq_mhz,
            "magnitude": magnitude,
            "band": band,
            "verdict": verdict,
            "center_hz": center_hz,
            "if_offset_hz": if_offset_hz,
            "fft_bins": fft_bins,
            "bin_index": bin_index
        });

        if let Ok(mut f) = std::fs::OpenOptions::new()
            .append(true)
            .create(true)
            .open("resolutions.jsonl")
        {
            let _ = writeln!(f, "{}", json);
        }

        let md_exists = std::path::Path::new("resolutions.md").exists();
        if let Ok(mut f) = std::fs::OpenOptions::new()
            .append(true)
            .create(true)
            .open("resolutions.md")
        {
            if !md_exists {
                let _ = writeln!(
                    f,
                    "| Time | MHz | Band | Class | Mag | IF Hz | Verdict |\n|---|---:|---|---|---:|---:|---|"
                );
            }
            let _ = writeln!(
                f,
                "| {} | {:.3} | {} | {} | {:.2} | {} | {} |",
                now.format("%H:%M:%S"),
                freq_mhz,
                band,
                classification,
                magnitude,
                if_offset_hz,
                verdict
            );
        }
    }

    fn plaintext_resolve(&mut self, freq_hz: u64, _mag: f32) {
        if let Some(band) = Self::band_label(freq_hz) {
            if band.starts_with("Pager") {
                self.log(format!(
                    "RESOLVE: {} carrier; plaintext needs POCSAG/FLEX decoder",
                    band
                ));
            } else {
                self.log(format!("RESOLVE: {} carrier; no decoded payload yet", band));
            }
        }
    }

    /// Downsample row-major grayscale `data` of size `src_w × src_h` into `dst_w × dst_h` ASCII lines using `ramp` and Bayer dithering.
    fn sample_grayscale_raster(
        data: &[u8],
        src_w: usize,
        src_h: usize,
        dst_w: usize,
        dst_h: usize,
        ramp: &str,
    ) -> String {
        let mut out = String::new();
        if data.is_empty() || src_w == 0 || src_h == 0 {
            return out;
        }

        // 4x4 Bayer Matrix for dithering
        const BAYER_4X4: [f32; 16] = [
            0.0 / 16.0,
            8.0 / 16.0,
            2.0 / 16.0,
            10.0 / 16.0,
            12.0 / 16.0,
            4.0 / 16.0,
            14.0 / 16.0,
            6.0 / 16.0,
            3.0 / 16.0,
            11.0 / 16.0,
            1.0 / 16.0,
            9.0 / 16.0,
            15.0 / 16.0,
            7.0 / 16.0,
            13.0 / 16.0,
            5.0 / 16.0,
        ];

        let draw_h = dst_h.max(1);
        let draw_w = dst_w.max(1);
        for y in 0..draw_h {
            let sy = (y * src_h) / draw_h;
            for x in 0..draw_w {
                let sx = (x * src_w) / draw_w;
                let src_idx = sy
                    .saturating_mul(src_w)
                    .saturating_add(sx)
                    .min(data.len().saturating_sub(1));

                let v = data[src_idx] as f32 / 255.0;

                // Dithering adjustment
                let bayer_idx = (y % 4) * 4 + (x % 4);
                let threshold = BAYER_4X4[bayer_idx];
                let v_dithered = v + (threshold - 0.5) * 0.1; // Subtle dither
                let v_clamped = v_dithered.clamp(0.0, 1.0);

                let char_idx = (v_clamped * (ramp.len() - 1) as f32) as usize;
                out.push(ramp.chars().nth(char_idx).unwrap_or(' '));
            }
            out.push('\n');
        }
        out
    }

    fn project_to_2d(&mut self, width: usize, height: usize) -> String {
        self.rotation_rad += 0.05;

        if self.amplituhedron_mode {
            let rendered = self.render_amplituhedron(width, height);
            let dashboard = self.render_selftalk_dashboard();
            let drift_panel = self.render_residual_panel(width);
            let mut out =
                overlay_text_panel(rendered, &dashboard, width, 1, width.saturating_sub(30));
            out = overlay_text_panel(out, &drift_panel, width, 12, width.saturating_sub(30));
            return out;
        }

        if self.math_mode {
            let rendered = self.render_topological_manifold(width, height);
            let dashboard = self.render_selftalk_dashboard();
            let drift_panel = self.render_residual_panel(width);
            let mut out =
                overlay_text_panel(rendered, &dashboard, width, 1, width.saturating_sub(30));
            out = overlay_text_panel(out, &drift_panel, width, 12, width.saturating_sub(30));
            return out;
        }

        let mut out = String::new();

        if let Some(name) = &self.active_knot_name {
            out.push_str(&format!(
                "{} [ KNOT:{} {} {}]{}\x1b[K\n",
                AEON_DIM, AEON_RESET, AEON_BOLD, name, AEON_RESET
            ));
        }

        // 1. Sensory Priority (Spectrogram, NOAA, PNG - Phase 0/Non-Background)
        let now_ms = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_millis() as u64;
        let visual_frames: Vec<&PleromaticFrame> = self
            .fragments
            .values()
            .filter(|f| {
                f.phase != 2
                    && (f.is_spectrogram_waterfall()
                        || f.is_noaa_apt()
                        || f.is_png_embedded()
                        || matches!(
                            f.media_type,
                            PleromaticMediaType::Video | PleromaticMediaType::Image
                        ))
            })
            .collect();
        let sensory_frame = visual_frames
            .iter()
            .copied()
            .filter(|f| now_ms.saturating_sub(f.timestamp_ms) < 2000)
            .max_by_key(|f| f.timestamp_ms)
            .or_else(|| {
                visual_frames
                    .iter()
                    .copied()
                    .filter(|f| f.is_noaa_apt())
                    .max_by_key(|f| f.timestamp_ms)
            })
            .or_else(|| visual_frames.iter().copied().max_by_key(|f| f.timestamp_ms));

        let is_fresh = if let Some(frame) = sensory_frame {
            now_ms.saturating_sub(frame.timestamp_ms) < 2000
        } else {
            false
        };

        let mut rendered = if let Some(frame) = sensory_frame {
            let is_visual_frame = frame.is_spectrogram_waterfall()
                || frame.is_noaa_apt()
                || frame.is_png_embedded()
                || matches!(
                    frame.media_type,
                    PleromaticMediaType::Video | PleromaticMediaType::Image
                );

            if is_fresh || is_visual_frame {
                match frame.media_type {
                    PleromaticMediaType::Video | PleromaticMediaType::Image => {
                        if frame.is_spectrogram_waterfall() {
                            let mut s = self.render_spectrum_waterfall(frame, width, height);
                            s = self.with_noaa_picture_in_picture(s, frame, width, height);
                            s
                        } else if frame.is_noaa_apt() {
                            self.render_noaa_apt(frame, width, height)
                        } else if frame.is_png_embedded() {
                            let mut s = self.render_png_image(frame, width, height);
                            s = self.with_noaa_picture_in_picture(s, frame, width, height);
                            s
                        } else {
                            self.render_pixels(frame, width, height)
                        }
                    }
                    PleromaticMediaType::Audio => self.render_voice(frame, width, height),
                    PleromaticMediaType::Semantic => self.render_semantic(frame, width, height),
                    PleromaticMediaType::Fingerprint => {
                        self.render_fingerprint(frame, width, height)
                    }
                    PleromaticMediaType::Application => {
                        self.render_application(frame, width, height)
                    }
                    _ => format!(
                        "{} [ {} FRAME {} ] {}\x1b[K",
                        AEON_DIM, frame.source_id, frame.seq, AEON_RESET
                    ),
                }
            } else {
                self.render_ghost_static(width, height)
            }
        } else if !self.baseline_floor.is_empty() {
            self.render_ghost_static(width, height)
        } else if !self.sieve.space.voxels.is_empty() {
            self.render_handshake_cloud(width, height)
        } else {
            self.render_ghost_static(width, height)
        };

        // Overlay Self-Talk Dashboard
        let dashboard = self.render_selftalk_dashboard();
        rendered = overlay_text_panel(rendered, &dashboard, width, 1, width.saturating_sub(30));

        out.push_str(&rendered);
        out
    }

    fn render_selftalk_dashboard(&self) -> TextPanel {
        let mut lines = Vec::new();
        let f = &self.fsm.state;

        let phase_str = match f.phase {
            SelfTalkPhase::Fork => "FORK (THROW)",
            SelfTalkPhase::Race => "RACE (COMPETE)",
            SelfTalkPhase::Fold => "FOLD (RECONCILE)",
        };

        lines.push("┌─── SELF-TALK RUNTIME ───┐".to_string());
        lines.push(format!("│ PHASE:  {:<16} │", phase_str));
        lines.push(format!("│ ENERGY: {:3}/100          │", f.energy));
        lines.push(format!("│ CONSC:  {:3}/5            │", f.consciousness));
        lines.push(format!("│ FOLD:   {:2}/8            │", f.fold_level));
        lines.push(format!("│ PITCH:  {:2}/12           │", f.pitch_class));
        lines.push("│ MEMORY: ACTIVE (.knot)   │".to_string());
        lines.push("└──────────────────────────┘".to_string());

        TextPanel { width: 28, lines }
    }

    fn render_residual_panel(&self, _width: usize) -> TextPanel {
        let mut lines = Vec::new();
        let residuals = &self.fsm.state.latent_drift;

        lines.push("┌─── LATENT DRIFT (PARIS) ──┐".to_string());

        // Show only a few key layers to save space in the panel
        let key_layers = [0, 3, 10, 18, 40, 79];
        for &l in &key_layers {
            let res = residuals.get(l).cloned().unwrap_or(0.0);
            let indicator = if res > 10.0 {
                "!!!"
            } else if res > 1.0 {
                "~~ "
            } else {
                "   "
            };
            lines.push(format!(
                "│ L{:02}: {:5.2} {}             │",
                l, res, indicator
            ));
        }

        if let Some(id) = self.fsm.state.argmax_id {
            let anchor = if id == 12366 { "PARIS" } else { "ERROR" };
            lines.push(format!("│ ARGMAX: {:<17} │", anchor));
        } else {
            lines.push("│ ARGMAX: PENDING...        │".to_string());
        }

        lines.push("└───────────────────────────┘".to_string());

        TextPanel { width: 28, lines }
    }

    fn render_amplituhedron(&self, width: usize, height: usize) -> String {
        let mut out = String::new();
        out.push_str(&draw_box_header(
            "GRASSMANNIAN AMPLITUHEDRON // O(1) VOLUME",
            width,
            AEON_AMBER,
        ));

        let draw_h = height.saturating_sub(2).max(1);
        let resolution = draw_h.min(width / 2).max(12);
        let mut voxels = vec![vec![vec![0.0_f32; resolution]; resolution]; resolution];
        let mut path_voxels = vec![vec![vec![false; resolution]; resolution]; resolution];

        // Dynamic properties based on the mesh + LIVE SIGNAL ENERGY
        let mut k = 4.0;
        let mut static_vol = 14.0 + (self.signal_energy * 20.0); // Modulate volume with energy
        let mut faces = 0;
        let mut tokens = Vec::new();

        if let Some(frame) = self
            .fragments
            .values()
            .find(|f| f.media_type == PleromaticMediaType::Fingerprint)
        {
            k = frame.barcode.beta1 as f32;
            static_vol = (frame.barcode.dilation * 10.0) + (self.signal_energy * 15.0);
            faces = frame.seq as usize;
            if let Ok(path) = bincode::deserialize::<MonsterPath>(&frame.data) {
                tokens = path;
            }
        }

        let n = if k > 0.0 { static_vol / k } else { 0.0 };
        let max_radius = resolution as f32 / 2.0;
        // The base radius "breathes" with the signal
        let base_radius = max_radius.min(2.0_f32.max((n * k) % max_radius));

        let cx = resolution as f32 / 2.0;
        let cy = resolution as f32 / 2.0;
        let cz = resolution as f32 / 2.0;

        // High energy increases facet jitter
        let facet_freq = 1.0_f32.max(k % 12.0) + (self.signal_energy * 2.0);
        let viewpoint = self.rotation_rad;

        // 1. Trace the topological path through the 3D volume
        let mut px = cx;
        let mut py = cy;
        let mut pz = cz;
        for (i, token) in tokens.iter().enumerate() {
            let step = 1.5;
            let angle = (i as f32 * 0.5) + viewpoint;
            match token {
                SignalToken::T => {
                    py += step;
                }
                SignalToken::F { .. } => {
                    px += angle.cos() * step;
                    pz += angle.sin() * step;
                }
                SignalToken::L => {
                    px -= (px - cx) * 0.5;
                    py -= (py - cy) * 0.5;
                    pz -= (pz - cz) * 0.5;
                }
                SignalToken::W { .. } => {
                    py += step * 3.0;
                }
                _ => {
                    py += step;
                }
            }

            let vx = (px as usize).min(resolution - 1);
            let vy = (py as usize).min(resolution - 1);
            let vz = (pz as usize).min(resolution - 1);
            path_voxels[vx][vy][vz] = true;
        }

        // 2. Slice the hyper-jewel into a 3D Plücker volume
        voxels.par_iter_mut().enumerate().for_each(|(x, plane)| {
            for y in 0..resolution {
                for z in 0..resolution {
                    let dx = x as f32 - cx;
                    let dy = y as f32 - cy;
                    let dz = z as f32 - cz;

                    let rx = dx * viewpoint.cos() - dz * viewpoint.sin();
                    let rz = dx * viewpoint.sin() + dz * viewpoint.cos();

                    let distance = (rx * rx + dy * dy + rz * rz).sqrt();
                    let angular_defect = (facet_freq * dy.atan2(rx)).cos();
                    let boundary_radius = base_radius + (angular_defect * 2.0) - (faces % 3) as f32;

                    if distance <= boundary_radius {
                        let density = 1.0 - (distance / boundary_radius);
                        plane[y][z] = density.clamp(0.0, 1.0);
                    }
                }
            }
        });

        // 3. Project 3D slice onto 2D ASCII terminal
        let chars = [' ', '.', ':', '-', '=', '+', '*', '#', '%', '@', '█'];
        let energy_bar_len = (self.signal_energy * 20.0) as usize;
        let energy_bar = format!(
            "{}{}{}",
            AEON_CYAN,
            "■".repeat(energy_bar_len),
            "□".repeat(20 - energy_bar_len)
        );

        for y in 0..draw_h {
            let mut row = String::new();

            // HUD Overlay for Amplituhedron mode
            let hud_row = match y {
                0 => Some(format!(
                    "{} ┌ OPERATOR SEQUENCE ┐ {}",
                    AEON_GHOST, AEON_RESET
                )),
                1 => Some(format!(
                    "{} │ BETA-1: {:04}      │ {}",
                    AEON_GHOST, k as u32, AEON_RESET
                )),
                2 => Some(format!(
                    "{} │ SIGNAL: {}  │ {}",
                    AEON_GHOST, energy_bar, AEON_RESET
                )),
                3 => Some(format!(
                    "{} └───────────────────┘ {}",
                    AEON_GHOST, AEON_RESET
                )),
                _ => None,
            };

            let hud_vis_len = 23;
            if let Some(hud) = hud_row {
                row.push_str(&hud);
            }

            if y < resolution {
                let start_x = if y < 4 { hud_vis_len / 2 } else { 0 };
                for x in start_x..resolution {
                    let mut max_density = 0.0_f32;
                    let mut is_path = false;
                    for z in 0..resolution {
                        if voxels[x][y][z] > max_density {
                            max_density = voxels[x][y][z];
                        }
                        if path_voxels[x][y][z] {
                            is_path = true;
                        }
                    }

                    let idx = (max_density * (chars.len() - 1) as f32).floor() as usize;
                    let c = if is_path { '☼' } else { chars[idx] };

                    let color = if is_path {
                        AEON_GREEN
                    } else if max_density > 0.8 {
                        AEON_AMBER
                    } else if max_density > 0.4 {
                        AEON_CYAN
                    } else {
                        AEON_GHOST
                    };

                    row.push_str(color);
                    row.push(c);
                    row.push(c);
                    row.push_str(AEON_RESET);
                }
            }

            out.push_str(&row);
            out.push_str("\x1b[K\n");
        }

        out.push_str(&draw_box_footer(width, AEON_AMBER));
        out
    }

    fn render_topological_manifold(&self, width: usize, height: usize) -> String {
        let mut out = String::new();
        out.push_str(&draw_box_header(
            "TOPOLOGICAL MANIFOLD // COBORDISM MAP",
            width,
            AEON_CYAN,
        ));

        let draw_h = height.saturating_sub(2).max(1);
        let mut canvas = vec![vec![' '; width]; draw_h];

        // Animate downward flow based on time
        let offset = (self.rotation_rad * 4.0) as usize;

        // Use the deepest fingerprint frame if available, otherwise use a synthetic mock path.
        let mut tokens = vec![
            SignalToken::T,
            SignalToken::F { r: 3 },
            SignalToken::R { r: 3 },
            SignalToken::W { m: 12 },
            SignalToken::L,
            SignalToken::S,
            SignalToken::V,
        ];
        let mut beta1 = 4;
        let mut dilation = 1.618;

        if let Some(frame) = self
            .fragments
            .values()
            .find(|f| f.media_type == PleromaticMediaType::Fingerprint)
        {
            if let Ok(path) = bincode::deserialize::<MonsterPath>(&frame.data) {
                tokens = path;
            }
            beta1 = frame.barcode.beta1;
            dilation = frame.barcode.dilation;
        } else {
            // Expand mock path if beta1 is high
            for _ in 0..beta1 {
                tokens.push(SignalToken::F { r: 1 });
                tokens.push(SignalToken::L);
            }
            tokens.push(SignalToken::V);
        }

        // Draw the flow tree
        let center_x = width / 2;
        let mut branches: Vec<(usize, usize)> = vec![(center_x, 0)]; // (x, length)

        for y in 0..draw_h {
            let virtual_y = y.wrapping_add(offset) % tokens.len().max(1);
            let token = &tokens[virtual_y];

            // Draw current active branches
            let mut next_branches = Vec::new();
            for &(x, _) in &branches {
                if x < width {
                    match token {
                        SignalToken::T => {
                            canvas[y][x] = '│';
                            next_branches.push((x, y));
                        }
                        SignalToken::F { r } => {
                            // Expand spread dynamically based on width to fill the screen
                            let max_spread = (width / 2).saturating_sub(4);
                            let spread = (*r as usize * 4).max(2).min(max_spread);

                            let left_x = x.saturating_sub(spread);
                            let right_x = (x + spread).min(width - 1);

                            if left_x < x {
                                canvas[y][left_x] = '┌';
                                next_branches.push((left_x, y));
                                for i in (left_x + 1)..x {
                                    canvas[y][i] = '─';
                                }
                            }

                            canvas[y][x] = '┼';
                            next_branches.push((x, y));

                            if right_x > x {
                                canvas[y][right_x] = '┐';
                                next_branches.push((right_x, y));
                                for i in (x + 1)..right_x {
                                    canvas[y][i] = '─';
                                }
                            }
                        }
                        SignalToken::R { .. } => {
                            canvas[y][x] = '║';
                            next_branches.push((x, y));
                        }
                        SignalToken::W { m } => {
                            canvas[y][x] = '╎';
                            next_branches.push((x, y));

                            // Draw the wormhole arc relative to the modulus, scaling with width
                            if dilation > 1.0 {
                                let arc_distance = (*m as usize * 2).min(width / 4);
                                let arc_x = (x + arc_distance).min(width - 1);
                                if arc_x > x + 1 {
                                    canvas[y][arc_x] = '│';
                                }
                            }
                        }
                        SignalToken::L => {
                            // Fold back toward center with a bias
                            let target_x = if x < center_x {
                                x + (center_x - x) / 2
                            } else if x > center_x {
                                x - (x - center_x) / 2
                            } else {
                                center_x
                            };

                            if x < target_x {
                                canvas[y][x] = '└';
                                for i in (x + 1)..target_x {
                                    canvas[y][i] = '─';
                                }
                                canvas[y][target_x] = '┐';
                                next_branches.push((target_x, y));
                            } else if x > target_x {
                                canvas[y][x] = '┘';
                                for i in (target_x + 1)..x {
                                    canvas[y][i] = '─';
                                }
                                canvas[y][target_x] = '┌';
                                next_branches.push((target_x, y));
                            } else {
                                canvas[y][x] = '┴';
                                next_branches.push((x, y));
                            }
                        }
                        SignalToken::S => {
                            canvas[y][x] = '╫';
                            next_branches.push((x, y));
                        }
                        SignalToken::V => {
                            canvas[y][x] = '▼';
                            // Probabilistically restart branches to keep the screen busy
                            if next_branches.is_empty() || (y + x) % 7 == 0 {
                                next_branches.push((center_x, y));
                            }
                        }
                    }
                }
            }

            // Limit branch count to avoid filling the screen entirely
            branches = next_branches.into_iter().take(8).collect();
            if branches.is_empty() {
                branches.push((center_x, y));
            }
        }

        // Render to string with colors
        let time_now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_secs_f64();

        for (y, row) in canvas.iter().enumerate() {
            // Iridescent Truecolor Gradient based on position and exact Gnosis time (12 BPM)
            // 12 breaths per minute = 1 cycle every 5 seconds = 0.2 Hz
            let breath_phase = (time_now * 0.2).fract() as f32;
            let phase = (y as f32 / draw_h as f32) * 1.5 - breath_phase;

            let r = ((phase * std::f32::consts::TAU).sin() * 127.0 + 128.0) as u8;
            let g = (((phase + 0.33) * std::f32::consts::TAU).sin() * 127.0 + 128.0) as u8;
            let b = (((phase + 0.66) * std::f32::consts::TAU).sin() * 127.0 + 128.0) as u8;
            let color = format!("\x1b[38;2;{};{};{}m", r, g, b);

            let mut styled_line = String::new();
            styled_line.push_str(&color);
            styled_line.push_str(&row.iter().collect::<String>());
            styled_line.push_str(AEON_RESET);

            // Overlay HUD for metrics
            let is_hud_row = y < 4;
            let hud_content = if is_hud_row {
                match y {
                    0 => Some(format!(
                        "{} ┌ OPERATOR SEQUENCE ┐ {}",
                        AEON_GHOST, AEON_RESET
                    )),
                    1 => Some(format!(
                        "{} │ BETA-1: {:04}      │ {}",
                        AEON_GHOST, beta1, AEON_RESET
                    )),
                    2 => Some(format!(
                        "{} │ DILATION: {:.2}    │ {}",
                        AEON_GHOST, dilation, AEON_RESET
                    )),
                    3 => Some(format!(
                        "{} └───────────────────┘ {}",
                        AEON_GHOST, AEON_RESET
                    )),
                    _ => None,
                }
            } else {
                None
            };

            let hud_vis_len = 23;
            if let Some(hud) = hud_content {
                out.push_str(&hud);
                if row.len() > hud_vis_len {
                    out.push_str(&color);
                    let remaining_chars: String = row.iter().skip(hud_vis_len).collect();
                    out.push_str(&remaining_chars);
                    out.push_str(AEON_RESET);
                }
            } else {
                out.push_str(&styled_line);
            }
            out.push('\n');
        }

        out.push_str(&draw_box_footer(width, AEON_CYAN));
        out
    }

    fn render_handshake_cloud(&self, width: usize, height: usize) -> String {
        let mut out = String::new();
        out.push_str(&draw_box_header(
            "MONSTER MESH HANDSHAKE",
            width,
            AEON_GREEN,
        ));
        let draw_h = height.saturating_sub(2).max(1);
        let mut canvas = vec![vec![' '; width]; draw_h];

        let view_stub = ProjectionView {
            view_id: "handshake".into(),
            angle_rad: self.rotation_rad,
            frame_data: Vec::new(),
            width,
            height: draw_h,
        };

        // Center point for the expansive projection
        let center = VoxelCoord {
            x: (width as i32 / 2),
            y: (draw_h as i32 / 2),
            z: 50,
        };

        for (coord, data) in &self.sieve.space.voxels {
            if data.is_path {
                let (u, v) = VirtualShutter::project(*coord, &view_stub, center);
                if u < width && v < draw_h {
                    let char = if coord.z > 50 {
                        '@'
                    } else if coord.z > 20 {
                        '*'
                    } else {
                        '.'
                    };
                    canvas[v][u] = char;
                }
            }
        }
        for row in canvas {
            out.push_str(AEON_GREEN);
            out.push_str(&row.iter().collect::<String>());
            out.push_str(AEON_RESET);
            out.push_str("\x1b[K\n");
        }
        out.push_str(&draw_box_footer(width, AEON_GREEN));
        out
    }

    fn render_png_image(&self, frame: &PleromaticFrame, width: usize, height: usize) -> String {
        let ramp = " .:-=+*#%@";
        let mut out = String::new();
        out.push_str(&draw_box_header("PNG IMAGE", width, AEON_BLUE));
        out.push_str(&format!(
            "{} SOURCE:{} {}\n",
            AEON_DIM, AEON_BLUE, frame.source_id
        ));
        match decode_png_to_grayscale_row_major(&frame.data) {
            Ok((data, img_w, img_h)) => {
                out.push_str(&format!(
                    "{} SOURCE_PX:{} {}x{}{}\n",
                    AEON_DIM, AEON_BLUE, img_w, img_h, AEON_RESET
                ));
                let draw_h = height.saturating_sub(3).max(1);
                let draw_w = width.max(1);
                let data_out =
                    Self::sample_grayscale_raster(&data, img_w, img_h, draw_w, draw_h, ramp);
                for line in data_out.lines() {
                    out.push_str(AEON_BLUE);
                    out.push_str(line);
                    out.push_str(AEON_RESET);
                    out.push('\n');
                }
            }
            Err(e) => {
                out.push_str(&format!(
                    "{} [ PNG DECODE ERROR: {} ] {}\n",
                    AEON_AMBER, e, AEON_RESET
                ));
            }
        }
        out.push_str(&draw_box_footer(width, AEON_BLUE));
        out
    }

    fn render_pixels(&self, frame: &PleromaticFrame, width: usize, height: usize) -> String {
        let ramp = " .:-=+*#%@";
        let mut out = String::new();
        out.push_str(&draw_box_header("IMAGE MANIFOLD", width, AEON_GHOST));
        if frame.data.is_empty() {
            return format!("{} [ EMPTY MANIFOLD ] {}\n", AEON_AMBER, AEON_RESET);
        }
        let draw_h = height.saturating_sub(2).max(1);
        for y in 0..draw_h {
            out.push_str(AEON_GHOST);
            for x in 0..width {
                let idx = (y * width + x) % frame.data.len();
                let val = frame.data[idx] as f32 / 255.0;
                let char_idx = (val * (ramp.len() - 1) as f32) as usize;
                out.push(ramp.chars().nth(char_idx).unwrap_or(' '));
            }
            out.push_str(AEON_RESET);
            out.push('\n');
        }
        out.push_str(&draw_box_footer(width, AEON_GHOST));
        out
    }

    fn render_semantic(&self, frame: &PleromaticFrame, width: usize, height: usize) -> String {
        let mut out = String::new();
        out.push_str(&draw_box_header("SEMANTIC SPACE", width, AEON_CYAN));
        let hidden_dim = frame
            .attributes
            .get("hidden_dim")
            .and_then(|s| s.parse::<usize>().ok())
            .unwrap_or(3584);
        let floats_in_data = frame.data.len() / 4;
        if floats_in_data == 0 {
            return out;
        }
        let draw_h = height.saturating_sub(2).max(1);
        let mut grid = vec![vec![' '; width]; draw_h];
        for i in 0..floats_in_data.min(hidden_dim) {
            let mut bytes = [0u8; 4];
            bytes.copy_from_slice(&frame.data[i * 4..(i + 1) * 4]);
            let val = f32::from_le_bytes(bytes);
            let x = (i * width / hidden_dim).min(width - 1);
            let y = (((val + 1.0) / 2.0) * draw_h as f32) as usize;
            let y = (draw_h - 1).saturating_sub(y).min(draw_h - 1);
            grid[y][x] = '.';
        }
        for row in grid {
            out.push_str(AEON_CYAN);
            out.push_str(&row.iter().collect::<String>());
            out.push_str(AEON_RESET);
            out.push('\n');
        }
        out.push_str(&draw_box_footer(width, AEON_CYAN));
        out
    }

    fn render_fingerprint(&self, frame: &PleromaticFrame, width: usize, _height: usize) -> String {
        let mut out = String::new();
        out.push_str(&draw_box_header(
            "TOPOLOGICAL FINGERPRINT",
            width,
            AEON_AMBER,
        ));
        if let Ok(path) = bincode::deserialize::<MonsterPath>(&frame.data) {
            let mut line = String::new();
            line.push_str(AEON_AMBER);
            line.push('[');
            for (i, token) in path.iter().enumerate() {
                if i > 0 {
                    line.push_str(", ");
                }
                match token {
                    SignalToken::T => line.push('T'),
                    SignalToken::F { r } => line.push_str(&format!("F({})", r)),
                    SignalToken::R { r } => line.push_str(&format!("R({})", r)),
                    SignalToken::L => line.push('L'),
                    SignalToken::S => line.push('S'),
                    SignalToken::W { m } => line.push_str(&format!("W({})", m)),
                    SignalToken::V => line.push('V'),
                }
                if line.len() > width + 10 {
                    // adjust for ANSI
                    out.push_str(&line);
                    out.push_str(AEON_RESET);
                    out.push('\n');
                    line = format!("{}  ", AEON_AMBER);
                }
            }
            line.push(']');
            out.push_str(&line);
            out.push_str(AEON_RESET);
            out.push('\n');
        } else {
            out.push_str(&format!(
                "{} [ INVALID FINGERPRINT DATA ] {}\n",
                AEON_AMBER, AEON_RESET
            ));
        }
        out.push_str(&draw_box_footer(width, AEON_AMBER));
        out
    }

    fn render_application(&self, frame: &PleromaticFrame, width: usize, height: usize) -> String {
        let mut out = String::new();
        out.push_str(&draw_box_header(
            &format!("APP: {}", frame.source_id),
            width,
            AEON_GREEN,
        ));
        if let Ok(state) = bincode::deserialize::<AppState>(&frame.data) {
            out.push_str(&format!("{} COMPONENTS:{}\n", AEON_DIM, AEON_RESET));
            for (key, val) in &state.components {
                out.push_str(&format!(
                    "{}  - {}: {}{}\n",
                    AEON_GREEN, key, AEON_RESET, val
                ));
            }
            out.push_str(&format!(
                "{} ACTIVE EXECUTION MANIFOLD:{}\n",
                AEON_DIM, AEON_RESET
            ));
            let draw_h = height.saturating_sub(4 + state.components.len()).max(1);
            let mut grid = vec![vec![' '; width]; draw_h];
            for coord in &state.active_coords {
                let x = (coord.x as usize).min(width - 1);
                let y = (coord.y as usize).min(draw_h - 1);
                grid[y][x] = 'X';
            }
            for row in grid {
                out.push_str(AEON_GREEN);
                out.push_str(&row.iter().collect::<String>());
                out.push_str(AEON_RESET);
                out.push('\n');
            }
        }
        out.push_str(&draw_box_footer(width, AEON_GREEN));
        out
    }

    fn render_noaa_apt(&self, frame: &PleromaticFrame, width: usize, height: usize) -> String {
        let ramp = " .:-=+*#%@";
        let mut out = String::new();
        let apt_w = frame
            .attributes
            .get("apt_width")
            .and_then(|v| v.parse::<usize>().ok())
            .unwrap_or(width.max(1));
        let apt_h = frame
            .attributes
            .get("apt_height")
            .and_then(|v| v.parse::<usize>().ok())
            .unwrap_or_else(|| frame.data.len().checked_div(apt_w.max(1)).unwrap_or(0));
        let center_hz = frame.attributes.get("rf_center_hz").cloned();
        let sync = frame
            .attributes
            .get("apt_sync")
            .map(String::as_str)
            .unwrap_or("unknown");
        let quality = frame
            .attributes
            .get("apt_quality")
            .map(String::as_str)
            .unwrap_or("?");
        let stability = frame
            .attributes
            .get("apt_stability")
            .map(String::as_str)
            .unwrap_or("?");

        out.push_str(&draw_box_header(
            "NOAA APT SCANLINE RECONSTRUCTION",
            width,
            AEON_AMBER,
        ));

        if let Some(ref hz) = center_hz {
            out.push_str(&format!(
                "{} RF_CENTER:{} {} Hz{}\n",
                AEON_DIM, AEON_AMBER, hz, AEON_RESET
            ));
        }
        out.push_str(&format!(
            "{} SOURCE:{} {}  DIM:{} {}x{}  SYNC:{} {}  Q:{} {}  STAB:{} {}{}\n",
            AEON_DIM,
            AEON_AMBER,
            frame.source_id,
            AEON_AMBER,
            apt_w,
            apt_h,
            AEON_AMBER,
            sync,
            AEON_AMBER,
            quality,
            AEON_AMBER,
            stability,
            AEON_RESET
        ));

        if frame.data.is_empty() || apt_w == 0 || apt_h == 0 {
            out.push_str(&format!(
                "{} [ EMPTY NOAA APT FRAME ] {}\n",
                AEON_AMBER, AEON_RESET
            ));
            return out;
        }

        if matches!(
            sync,
            "searching" | "silent" | "signal_no_sync" | "unstable_high_sens"
        ) && frame.source_id == "noaa_apt_live"
        {
            let state = match sync {
                "silent" => "APT CHANNEL SILENT: no usable audio energy",
                "signal_no_sync" => "RF/AUDIO PRESENT: no NOAA APT sync bars locked yet",
                "unstable_high_sens" => {
                    "HIGH SENS DEBUG: unstable sync offsets, not a decoded NOAA image"
                }
                _ => "APT SYNC SEARCHING: waiting for NOAA pass / stronger 2400 Hz subcarrier",
            };
            out.push_str(&format!("{} [ {} ] {}\n", AEON_AMBER, state, AEON_RESET));
        }

        let mut header_reserve = 3usize;
        if center_hz.is_some() {
            header_reserve += 1;
        }
        let draw_h = height.saturating_sub(header_reserve + 1).max(1);
        let draw_w = width.max(1);

        let data_out =
            Self::sample_grayscale_raster(&frame.data, apt_w, apt_h, draw_w, draw_h, ramp);

        let mut final_data = String::new();
        for line in data_out.lines() {
            final_data.push_str(AEON_AMBER);
            final_data.push_str(line);
            final_data.push_str(AEON_RESET);
            final_data.push('\n');
        }

        out.push_str(&final_data);
        out.push_str(&draw_box_footer(width, AEON_AMBER));
        out
    }

    fn with_noaa_picture_in_picture(
        &self,
        rendered: String,
        current_frame: &PleromaticFrame,
        width: usize,
        height: usize,
    ) -> String {
        if current_frame.is_noaa_apt() || width < 90 || height < 24 {
            return rendered;
        }

        let Some(noaa) = self.latest_noaa_frame() else {
            return rendered;
        };
        let Some(panel) = Self::render_noaa_pip(&noaa, width, height) else {
            return rendered;
        };

        overlay_text_panel(
            rendered,
            &panel,
            width,
            2,
            width.saturating_sub(panel.width + 2),
        )
    }

    fn latest_noaa_frame(&self) -> Option<PleromaticFrame> {
        self.fragments
            .values()
            .filter(|f| f.is_noaa_apt())
            .max_by_key(|f| f.timestamp_ms)
            .cloned()
    }

    fn render_noaa_pip(frame: &PleromaticFrame, width: usize, height: usize) -> Option<TextPanel> {
        let apt_w = frame
            .attributes
            .get("apt_width")
            .and_then(|v| v.parse::<usize>().ok())
            .unwrap_or(0);
        let apt_h = frame
            .attributes
            .get("apt_height")
            .and_then(|v| v.parse::<usize>().ok())
            .unwrap_or_else(|| frame.data.len().checked_div(apt_w.max(1)).unwrap_or(0));
        if frame.data.is_empty() || apt_w == 0 || apt_h == 0 {
            return None;
        }

        let panel_w = (width / 4).clamp(28, 52);
        let panel_h = (height / 4).clamp(10, 20);
        let inner_w = panel_w.saturating_sub(2).max(1);
        let inner_h = panel_h.saturating_sub(4).max(1);
        let ramp = " .:-=+*#%@";
        let raster =
            Self::sample_grayscale_raster(&frame.data, apt_w, apt_h, inner_w, inner_h, ramp);

        let mut lines = Vec::with_capacity(panel_h);
        lines.push(format!(
            "┌{:─<w$}┐",
            " NOAA IMAGE ",
            w = panel_w.saturating_sub(2)
        ));
        lines.push(format!(
            "│ {:<w$}│",
            format!(
                "{}x{} {} q={}",
                apt_w,
                apt_h,
                frame
                    .attributes
                    .get("apt_sync")
                    .map(String::as_str)
                    .unwrap_or("?"),
                frame
                    .attributes
                    .get("apt_quality")
                    .map(String::as_str)
                    .unwrap_or("?")
            ),
            w = panel_w.saturating_sub(3)
        ));
        for row in raster.lines().take(inner_h) {
            lines.push(format!("│{}│", pad_visible(row, inner_w)));
        }
        while lines.len() < panel_h.saturating_sub(1) {
            lines.push(format!("│{}│", " ".repeat(inner_w)));
        }
        lines.push(format!("└{}┘", "─".repeat(panel_w.saturating_sub(2))));

        Some(TextPanel {
            width: panel_w,
            lines,
        })
    }

    fn render_spectrum_waterfall(
        &self,
        frame: &PleromaticFrame,
        width: usize,
        height: usize,
    ) -> String {
        let ramp = " .:-=+*#%@";
        let mut out = String::new();
        let spec_w = frame
            .attributes
            .get("spec_width")
            .and_then(|v| v.parse::<usize>().ok())
            .unwrap_or(width.max(1));
        let spec_h = frame
            .attributes
            .get("spec_height")
            .and_then(|v| v.parse::<usize>().ok())
            .unwrap_or_else(|| frame.data.len().checked_div(spec_w.max(1)).unwrap_or(0));
        let iq_rate = frame
            .attributes
            .get("iq_rate_hz")
            .cloned()
            .unwrap_or_else(|| "?".into());
        let center_hz = frame.attributes.get("rf_center_hz").cloned();

        out.push_str(&draw_box_header("SPECTROGRAM WATERFALL", width, AEON_CYAN));

        // Clean, indented telemetry header with EOL clearing
        out.push_str(&format!(
            "  {}■{} IQ_RATE_HZ:{} {} Hz  {}│{} SPEC:{} {}x{}  {}│{} SOURCE:{} {}\x1b[K\n",
            AEON_DIM,
            AEON_RESET,
            AEON_CYAN,
            iq_rate,
            AEON_DIM,
            AEON_RESET,
            AEON_CYAN,
            spec_w,
            spec_h,
            AEON_DIM,
            AEON_RESET,
            AEON_CYAN,
            frame.source_id
        ));

        if let Some(ref hz) = center_hz {
            out.push_str(&format!(
                "  {}■{} RF_CENTER:{} {} Hz\x1b[K\n",
                AEON_DIM, AEON_RESET, AEON_AMBER, hz
            ));
        }

        // --- LIVE RESONANCE SCOPE (Sparkline) ---
        // Render the newest row of data as a high-energy green waveform
        if !frame.data.is_empty() {
            let spec_w = frame
                .attributes
                .get("spec_width")
                .and_then(|v| v.parse::<usize>().ok())
                .unwrap_or(512);
            let newest_row = &frame.data[frame.data.len().saturating_sub(spec_w)..];
            let mut scope = String::new();
            // Prefix + Scope width chosen for perfect center alignment with waterfall (width/2)
            scope.push_str(&format!(" {}■{} SCOPE: ", AEON_DIM, AEON_RESET));
            let scope_width = width.saturating_sub(11);
            for x in 0..scope_width {
                let sx = (x * spec_w) / scope_width;
                let val = newest_row.get(sx).copied().unwrap_or(0);
                let mag = val as f32 / 255.0;

                // Highlight the exact center of the scope
                if x == scope_width / 2 {
                    scope.push_str(AEON_AMBER);
                    scope.push('┃');
                    scope.push_str(AEON_GREEN);
                } else {
                    let chars = [' ', ' ', '▂', '▃', '▄', '▅', '▆', '▇', '█'];
                    let idx = (mag * (chars.len() - 1) as f32) as usize;
                    scope.push(chars[idx]);
                }
            }
            out.push_str(&scope);
            out.push_str(&format!("{}\x1b[K\n", AEON_RESET));
        }

        if let Some(v) = frame.attributes.get("mesh_best_if_offset_hz") {
            let score = frame
                .attributes
                .get("mesh_best_score")
                .map(|s| format!(" {}score={}{}", AEON_CYAN, s, AEON_RESET))
                .unwrap_or_default();
            out.push_str(&format!(
                "  {}■{} MESH_FOLD:{} best_if_hz={}{}\x1b[K\n",
                AEON_DIM, AEON_RESET, AEON_GREEN, v, score
            ));
        }

        out.push_str(&format!("{}{}\x1b[K\n", AEON_CYAN, "─".repeat(width)));

        if frame.data.is_empty() || spec_w == 0 || spec_h == 0 {
            out.push_str(&format!(
                "{} [ EMPTY SPECTROGRAM FRAME ] {}\x1b[K\n",
                AEON_AMBER, AEON_RESET
            ));
            return out;
        }

        let mut header_reserve = 5usize; // Header + SCOPE + separator
        if center_hz.is_some() {
            header_reserve += 1;
        }
        if frame.attributes.contains_key("mesh_best_if_offset_hz") {
            header_reserve += 1;
        }

        let draw_h = height.saturating_sub(header_reserve).max(1);
        let draw_w = width.max(1);

        // Scanning line effect
        let scan_y = (self.rotation_rad * 10.0) as usize % draw_h;
        let uptime_secs = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap()
            .as_secs_f64();

        // Sample grayscale but we'll use the raw values for color
        let mut row_major = vec![0u8; draw_w * draw_h];
        if !frame.data.is_empty() {
            row_major
                .par_chunks_mut(draw_w)
                .enumerate()
                .for_each(|(y, row)| {
                    let sy = (y * spec_h) / draw_h;
                    for x in 0..draw_w {
                        let sx = (x * spec_w) / draw_w;
                        let src_idx = sy * spec_w + sx;
                        if src_idx < frame.data.len() {
                            row[x] = frame.data[src_idx];
                        }
                    }
                });
        }

        // Parallelize line generation for maximum rendering speed
        // PRE-ALLOCATED ZERO-COPY BUFFER: we write directly into a large byte buffer
        let est_line_size = width * 32; // Increased for high ANSI density
        let mut final_data_bytes = vec![0u8; draw_h * est_line_size];

        // We use par_chunks_mut to write lines in parallel into the target buffer
        final_data_bytes
            .par_chunks_mut(est_line_size)
            .enumerate()
            .for_each(|(y, out_chunk)| {
                use std::fmt::Write;
                let mut styled_line = String::new();

                // HUD Overlay Logic
                let is_hud_row = y < 14;
                let hud_content = if is_hud_row {
                    match y {
                        0 => Some(format!(
                            "{} ┌ ANALYZING RESONANCE ─────────────┐ {}",
                            AEON_GHOST, AEON_RESET
                        )),
                        1 => Some(format!(
                            "{} │ BETA-1: {:04}                    │ {}",
                            AEON_GHOST, frame.barcode.beta1, AEON_RESET
                        )),
                        2 => Some(format!(
                            "{} │ DILATION: {:.2}                  │ {}",
                            AEON_GHOST, frame.barcode.dilation, AEON_RESET
                        )),
                        3 => {
                            let resolve = self
                                .resolved_events
                                .last()
                                .map(|e| {
                                    let s = format!(
                                        "{}: {:.1}MHz ({:.2})",
                                        e.classification,
                                        e.freq_hz as f32 / 1_000_000.0,
                                        e.magnitude
                                    );
                                    s.chars().take(25).collect::<String>()
                                })
                                .unwrap_or("NONE".into());
                            Some(format!(
                                "{} │ RESOLVE: {:<25} │ {}",
                                AEON_GHOST, resolve, AEON_RESET
                            ))
                        }
                        4 => {
                            let mut residue = "NONE".to_string();
                            if let Some(f) = self
                                .fragments
                                .values()
                                .filter(|f| f.media_type == PleromaticMediaType::Semantic)
                                .max_by_key(|f| f.timestamp_ms)
                            {
                                if let Ok(text) = String::from_utf8(f.data.clone()) {
                                    residue = text.chars().take(25).collect();
                                }
                            }
                            Some(format!(
                                "{} │ RESIDUE: {:<25} │ {}",
                                AEON_GHOST, residue, AEON_RESET
                            ))
                        }
                        5 => {
                            let knot = self.active_knot_name.as_deref().unwrap_or("NONE");
                            let status = format!("{} FRAGS / {}", self.fragments.len(), knot);
                            let status_trunc: String = status.chars().take(25).collect();
                            Some(format!(
                                "{} │ MESH: {:<25} │ {}",
                                AEON_GHOST, status_trunc, AEON_RESET
                            ))
                        }
                        6 => Some(format!(
                            "{} │ S-GAIN: {:.1}x                    │ {}",
                            AEON_GHOST, self.software_gain, AEON_RESET
                        )),
                        7 => Some(format!(
                            "{} │ RES-TH: {:.3}                   │ {}",
                            AEON_GHOST, self.noise_threshold, AEON_RESET
                        )),
                        8 => Some(format!(
                            "{} └──────────────────────────────────┘ {}",
                            AEON_GHOST, AEON_RESET
                        )),
                        9 => Some(format!(
                            "{} [ DEEP TELEMETRY ]                {}",
                            AEON_GHOST, AEON_RESET
                        )),
                        10..=15 => {
                            let log_idx = y - 10;
                            let recent_logs = &self.logs;
                            if recent_logs.len() > log_idx {
                                let log =
                                    &recent_logs[recent_logs.len().saturating_sub(6) + log_idx];
                                let trunc_log: String = log.chars().take(30).collect();
                                Some(format!(
                                    "{}   {:<30}  {}",
                                    AEON_GHOST, trunc_log, AEON_RESET
                                ))
                            } else {
                                None
                            }
                        }
                        _ => None,
                    }
                } else {
                    None
                };

                let hud_vis_len = 35;

                let wave_x_offset = if self.horizontal_waves {
                    ((y as f32 * 0.15 + uptime_secs as f32 * 4.0).sin() * 4.0) as i32
                } else {
                    0
                };

                if let Some(hud) = hud_content {
                    styled_line.push_str(&hud);
                }

                // Fix Right-Edge Wrap: Ensure we don't exceed terminal width
                let draw_w_clipped = draw_w.saturating_sub(1);

                for x in 0..draw_w_clipped {
                    let lookup_x = if self.horizontal_waves {
                        (x as i32 - wave_x_offset).rem_euclid(draw_w as i32) as usize
                    } else {
                        x
                    };

                    if is_hud_row && x < hud_vis_len {
                        continue;
                    }

                    let val = row_major[y * draw_w + lookup_x];
                    let mag = (val as f32 / 255.0 * self.software_gain).min(1.0);

                    // --- PHOSPHOR PERSISTENCE ENGINE ---
                    // Vertical distance *backwards* from scanline (trailing smear)
                    let dist_behind_scan = (scan_y as i32 - y as i32).rem_euclid(draw_h as i32);
                    let phosphor_falloff =
                        (1.0 - (dist_behind_scan as f32 / draw_h as f32).powf(0.3)).max(0.1);

                    // --- KINETIC WAVE LINE ---
                    // The scanline vertically modulates based on signal magnitude
                    let wave_mod = (mag * 1.5 * 12.0) as i32;
                    let is_scan_wave =
                        (y as i32) == (scan_y as i32 - wave_mod).rem_euclid(draw_h as i32);

                    // --- SPATIAL SNR LOCK ---
                    // Calculate local noise floor from neighbors to determine true SNR
                    let mut neighbor_sum = 0.0;
                    let neighbor_count = 10;
                    for i in 1..=(neighbor_count / 2) {
                        let nx_left =
                            (lookup_x as i32 - i).rem_euclid(draw_w as i32) as usize;
                        let nx_right =
                            (lookup_x as i32 + i).rem_euclid(draw_w as i32) as usize;
                        neighbor_sum += row_major[y * draw_w + nx_left] as f32 / 255.0;
                        neighbor_sum += row_major[y * draw_w + nx_right] as f32 / 255.0;
                    }
                    let local_noise = neighbor_sum / neighbor_count as f32;

                    // Signal is "Intelligent" if it's 15% brighter than its neighborhood
                    // and above the global threshold.
                    let has_carrier = mag > local_noise + 0.15 && mag > self.noise_threshold;

                    if is_scan_wave {
                        styled_line.push_str(AEON_GREEN);
                        styled_line.push_str(AEON_BOLD);
                    } else if has_carrier {
                        styled_line.push_str(AEON_CYAN);
                        styled_line.push_str(AEON_BOLD);
                    } else if x == draw_w / 2 {
                        // CENTER RETICLE: Faint vertical line at center frequency
                        styled_line.push_str(AEON_DIM);
                        styled_line.push_str(AEON_GHOST);
                    } else {
                        let r = (mag.powi(3) * 255.0 * phosphor_falloff) as u8;
                        let g = (mag * 210.0 * phosphor_falloff).max(mag * 255.0 * 0.1) as u8;
                        let b = (mag * 255.0 * phosphor_falloff).max(30.0) as u8;
                        write!(styled_line, "\x1b[38;2;{};{};{}m", r, g, b).unwrap();
                    };

                    let char_idx = (mag * (ramp.len() - 1) as f32) as usize;
                    styled_line.push(ramp.chars().nth(char_idx).unwrap_or(' '));
                }
                styled_line.push_str(AEON_RESET);
                styled_line.push_str("\x1b[K\n");

                // Copy line into pre-allocated slice
                let bytes = styled_line.as_bytes();
                let len = bytes.len().min(out_chunk.len());
                out_chunk[..len].copy_from_slice(&bytes[..len]);
            });

        // Combine by filtering out the null padding from pre-allocation
        for chunk in final_data_bytes.chunks(est_line_size) {
            let line_bytes = match chunk.iter().position(|&b| b == 0) {
                Some(pos) => &chunk[..pos],
                None => chunk,
            };
            out.push_str(std::str::from_utf8(line_bytes).unwrap_or(""));
        }
        out
    }

    fn render_ghost_static(&self, width: usize, height: usize) -> String {
        let mut out = String::new();
        out.push_str(&draw_box_header(
            "SEARCHING FOR RESONANCE",
            width,
            AEON_GHOST,
        ));
        let draw_h = height.saturating_sub(2).max(1);

        let scan_y = (self.rotation_rad * 5.0) as usize % draw_h;

        for y in 0..draw_h {
            out.push_str(if y == scan_y { AEON_CYAN } else { AEON_GHOST });
            for x in 0..width {
                // Procedural noise with "Spectral Phantoms" (vertical bias)
                let noise = ((x as f32 * 0.123 + y as f32 * 0.456 + self.rotation_rad).sin()
                    * 1000.0)
                    .fract();
                let phantom = ((x as f32 * 0.05 + self.rotation_rad * 0.5).sin() * 50.0).fract();

                if noise > 0.99 || (phantom > 0.98 && noise > 0.8) {
                    out.push('░');
                } else if noise > 0.96 || (phantom > 0.95 && noise > 0.7) {
                    out.push('·');
                } else {
                    out.push(' ');
                }
            }
            out.push_str(AEON_RESET);
            out.push_str("\x1b[K\n");
        }
        out.push_str(&draw_box_footer(width, AEON_GHOST));
        out
    }

    fn render_voice(&self, frame: &PleromaticFrame, width: usize, _height: usize) -> String {
        let mut out = String::new();
        out.push_str(" [ PNEUMA VOICE CODEC ] \n");
        if frame.data.is_empty() {
            return out;
        }
        match frame.data[0] {
            voice_codecs::PHONEME_TAG => {
                let ids = voice_codecs::decode_phonemes(&frame.data);
                out.push_str(&format!(" PHONEMES: {:?}\n", ids));
            }
            voice_codecs::PROSODY_TAG => {
                let frames = voice_codecs::decode_prosody(&frame.data);
                out.push_str(" PROSODY (f0):\n");
                let mut sparkline = String::new();
                for f in frames.iter().take(width) {
                    let char_idx = (f.f0_bin as usize * 7 / 64).min(6);
                    sparkline.push([' ', '.', ':', '-', '=', '+', '*', '#'][char_idx]);
                }
                out.push_str(&sparkline);
                out.push('\n');
            }
            _ => out.push_str(" [ UNKNOWN VOICE DATA ] \n"),
        }
        out
    }
}

// =====================================================================
// SKYMESH VIEW
// ---------------------------------------------------------------------
// Two air-gapped RTL-SDR stations both hear the same ambient RF, both
// derive the same witness, both teleport the SAME answer with NO link
// between them. This view renders the frame.json contract
// (`gnosis.skymesh.v1`) as a 2-pane terminal display, mirroring the
// aeon-monitor ANSI / box-drawing idiom (no emojis, ASCII badges only).
// =====================================================================

const SKYMESH_DEFAULT_FRAME: &str = ".qa-artifacts/skymesh/frame.json";

// Default serve port for the Skymesh frame server (the web app's default).
const SKYMESH_DEFAULT_SERVE_PORT: u16 = 8722;

#[derive(Debug, Clone, Serialize, Deserialize)]
struct SkymeshStation {
    id: String,
    #[serde(default)]
    witness: f64,
    #[serde(default, rename = "witnessLocked")]
    witness_locked: bool,
    #[serde(default)]
    projection: f64,
    #[serde(default, rename = "geodesicLength")]
    geodesic_length: f64,
    #[serde(default)]
    token: Option<String>,
    #[serde(default)]
    state: String,
    #[serde(default)]
    spectrum: Vec<f64>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct SkymeshAirGap {
    #[serde(default, rename = "linkBetweenStations")]
    link_between_stations: bool,
    #[serde(default)]
    proof: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct SkymeshFrame {
    #[serde(default, rename = "schemaVersion")]
    schema_version: String,
    #[serde(default)]
    stations: Vec<SkymeshStation>,
    #[serde(default, rename = "airGap")]
    air_gap: Option<SkymeshAirGap>,
    #[serde(default, rename = "match")]
    matched: bool,
}

/// Built-in fixture so the view renders with NO orchestrator running.
/// Returns a frame for animation step `t` (LISTENING -> WITNESS_LOCKED
/// -> TELEPORTED) so `--demo` can rehearse the full lockstep moment.
fn skymesh_fixture(t: usize) -> SkymeshFrame {
    // Both stations share one ambient sky; spectra are derived from the
    // same seed so they look near-identical (the visceral point).
    let phase = (t as f64) * 0.18;
    let make_spectrum = |jitter: f64| -> Vec<f64> {
        (0..48)
            .map(|i| {
                let f = i as f64;
                // A shared carrier near bin 24 plus shared low harmonics.
                let carrier = (-((f - 24.0).powi(2)) / 36.0).exp();
                let wash = ((f * 0.4 + phase).sin() * 0.5 + 0.5) * 0.35;
                let n = (((f * 12.9898 + jitter + phase).sin() * 43758.547).fract()).abs() * 0.08;
                (carrier + wash + n).min(1.0)
            })
            .collect()
    };

    // State machine across the demo timeline.
    let (state, witness_locked, token): (&str, bool, Option<String>) = if t < 12 {
        ("LISTENING", false, None)
    } else if t < 24 {
        ("WITNESS_LOCKED", true, None)
    } else {
        ("TELEPORTED", true, Some("Paris".to_string()))
    };

    let witness = if witness_locked { 66.0 } else { 0.0 };
    let projection = if witness_locked { 69.0 } else { 0.0 };

    let station = |id: &str, jitter: f64| SkymeshStation {
        id: id.to_string(),
        witness,
        witness_locked,
        projection,
        geodesic_length: 0.0,
        token: token.clone(),
        state: state.to_string(),
        spectrum: make_spectrum(jitter),
    };

    let matched = token.is_some();

    SkymeshFrame {
        schema_version: "gnosis.skymesh.v1".to_string(),
        stations: vec![station("STATION-A", 1.0), station("STATION-B", 2.0)],
        air_gap: Some(SkymeshAirGap {
            link_between_stations: false,
            proof: "no shared clock, no network, no cable -- only the sky".to_string(),
        }),
        matched,
    }
}

fn skymesh_read_frame(path: &str) -> Option<SkymeshFrame> {
    let data = std::fs::read_to_string(path).ok()?;
    serde_json::from_str::<SkymeshFrame>(&data).ok()
}

/// Color for a station state badge.
fn skymesh_state_color(state: &str) -> &'static str {
    match state {
        "TELEPORTED" => AEON_GREEN,
        "WITNESS_LOCKED" => AEON_CYAN,
        "DENIED" => AEON_AMBER,
        _ => AEON_GHOST, // LISTENING / unknown
    }
}

/// Fixed-width ASCII badge (no emojis) for a station state.
fn skymesh_state_badge(state: &str) -> String {
    let label = match state {
        "TELEPORTED" => "[ TELEPORTED   ]",
        "WITNESS_LOCKED" => "[ WITNESS LOCK ]",
        "DENIED" => "[ DENIED       ]",
        "LISTENING" => "[ LISTENING    ]",
        _ => "[ -----------  ]",
    };
    label.to_string()
}

/// Render a single station spectrum strip as stacked block rows.
/// `inner` is the usable width inside the pane. Returns `rows` lines.
fn skymesh_spectrum_strip(spectrum: &[f64], inner: usize, rows: usize) -> Vec<String> {
    let chars = [' ', '.', ':', '-', '=', '+', '*', '#', '%', '@'];
    let mut out = Vec::with_capacity(rows);
    if spectrum.is_empty() || inner == 0 {
        for _ in 0..rows {
            out.push(" ".repeat(inner));
        }
        return out;
    }
    for r in 0..rows {
        // Top row = highest band of the column's magnitude scale.
        let row_floor = (rows - 1 - r) as f64 / rows as f64;
        let mut line = String::with_capacity(inner);
        for x in 0..inner {
            let sx = (x * spectrum.len()) / inner.max(1);
            let mag = spectrum.get(sx).copied().unwrap_or(0.0).clamp(0.0, 1.0);
            if mag >= row_floor {
                // Sub-cell intensity from how far above the floor it sits.
                let over = ((mag - row_floor) / (1.0 / rows as f64)).clamp(0.0, 1.0);
                let idx = (over * (chars.len() - 1) as f64) as usize;
                line.push(chars[idx.min(chars.len() - 1)]);
            } else {
                line.push(' ');
            }
        }
        out.push(line);
    }
    out
}

/// Build one station pane as a vector of lines (without the shared border
/// column; the caller stitches A | gutter | B together).
fn skymesh_station_pane(
    st: Option<&SkymeshStation>,
    inner: usize,
    spec_rows: usize,
) -> Vec<String> {
    let mut lines: Vec<String> = Vec::new();
    let pad = |s: String| pad_visible(&s, inner);

    let st = match st {
        Some(s) => s,
        None => {
            for _ in 0..(spec_rows + 7) {
                lines.push(pad(String::new()));
            }
            return lines;
        }
    };

    let color = skymesh_state_color(&st.state);

    // Station id header.
    lines.push(format!(
        "{}{}{}{}",
        AEON_BOLD,
        pad(format!(" {}", st.id)),
        AEON_RESET,
        ""
    ));
    // State badge.
    lines.push(format!(
        "{}{}{}",
        color,
        pad(format!(" {}", skymesh_state_badge(&st.state))),
        AEON_RESET
    ));
    lines.push(pad(String::new()));

    // Spectrum strip header + waterfall.
    lines.push(format!(
        "{}{}{}",
        AEON_DIM,
        pad(" SKY SPECTRUM".to_string()),
        AEON_RESET
    ));
    let strip = skymesh_spectrum_strip(&st.spectrum, inner.saturating_sub(1), spec_rows);
    for s in strip {
        lines.push(format!(
            "{} {}{}",
            AEON_CYAN,
            pad_visible(&s, inner.saturating_sub(1)),
            AEON_RESET
        ));
    }
    lines.push(pad(String::new()));

    // Witness / projection / geodesic readouts.
    let witness_txt = if st.witness_locked {
        format!(" WITNESS  : {:>8.0}  [LOCKED]", st.witness)
    } else {
        format!(" WITNESS  : {:>8}  [open]", "--")
    };
    lines.push(format!("{}{}{}", color, pad(witness_txt), AEON_RESET));
    lines.push(pad(format!(
        " PROJECT  : {:>8.0}  GEODESIC: {:.0}",
        st.projection, st.geodesic_length
    )));

    // Big token when teleported.
    lines.push(pad(String::new()));
    if st.state == "TELEPORTED" {
        if let Some(tok) = &st.token {
            lines.push(format!(
                "{}{}{}{}",
                AEON_BOLD,
                AEON_GREEN,
                pad(format!("   >> {} <<", tok.to_uppercase())),
                AEON_RESET
            ));
        } else {
            lines.push(pad(String::new()));
        }
    } else if st.state == "DENIED" {
        lines.push(format!(
            "{}{}{}",
            AEON_AMBER,
            pad("   >> DENIED <<".to_string()),
            AEON_RESET
        ));
    } else {
        lines.push(pad(format!("{}   (awaiting teleport)", AEON_GHOST)));
    }

    lines
}

/// Render the whole Skymesh view to an ANSI string for the given TTY size.
fn render_skymesh(frame: &SkymeshFrame, width: usize, height: usize) -> String {
    let mut out = String::new();
    out.push_str(&draw_box_header(
        "SKYMESH // AIR-GAPPED TELEPORT",
        width,
        AEON_CYAN,
    ));

    // Two panes split with a center gutter.
    let gutter = 3usize; // " | "
    let pane_w = width.saturating_sub(gutter) / 2;
    let pane_w = pane_w.max(8);

    // Reserve rows for header(already)/center-banner/footer; size the
    // spectrum waterfall to fill the remaining height.
    let chrome_rows = 7; // id, badge, gap, spec-label, gap, witness, project, token-ish handled in pane
    let avail = height.saturating_sub(2); // header + footer already accounted by box helpers
    let spec_rows = avail.saturating_sub(chrome_rows + 4).clamp(3, 10);

    let st_a = frame.stations.first();
    let st_b = frame.stations.get(1);
    let pane_a = skymesh_station_pane(st_a, pane_w, spec_rows);
    let pane_b = skymesh_station_pane(st_b, pane_w, spec_rows);

    let rows = pane_a.len().max(pane_b.len());
    let empty = pad_visible("", pane_w);
    for i in 0..rows {
        let a = pane_a.get(i).cloned().unwrap_or_else(|| empty.clone());
        let b = pane_b.get(i).cloned().unwrap_or_else(|| empty.clone());
        out.push_str(&format!(
            "{}{} {}│{} {}{}\x1b[K\n",
            a, AEON_RESET, AEON_GHOST, AEON_RESET, b, AEON_RESET
        ));
    }

    // --- CENTER BANNER: NO LINK + air-gap proof + match indicator ---
    out.push_str(&format!("{}{}\x1b[K\n", AEON_GHOST, "─".repeat(width)));

    let air = frame.air_gap.as_ref();
    let no_link = air.map(|a| !a.link_between_stations).unwrap_or(true);
    let link_line = if no_link {
        format!(
            "{}{}      NO LINK BETWEEN THESE STATIONS      {}",
            AEON_BOLD, AEON_AMBER, AEON_RESET
        )
    } else {
        format!(
            "{}{}  WARNING: A LINK WAS DETECTED BETWEEN STATIONS  {}",
            AEON_BOLD, AEON_GREEN, AEON_RESET
        )
    };
    // Center the banner.
    let banner_plain = if no_link {
        "      NO LINK BETWEEN THESE STATIONS      "
    } else {
        "  WARNING: A LINK WAS DETECTED BETWEEN STATIONS  "
    };
    let lead = width.saturating_sub(banner_plain.len()) / 2;
    out.push_str(&format!("{}{}\x1b[K\n", " ".repeat(lead), link_line));

    if let Some(a) = air {
        if !a.proof.is_empty() {
            let proof = format!(" air-gap proof: {}", a.proof);
            out.push_str(&format!(
                "{}{}{}\x1b[K\n",
                AEON_DIM,
                pad_visible(&proof, width),
                AEON_RESET
            ));
        }
    }

    // Match indicator -- lights when both stations show the same token.
    let both_tokens: Vec<&String> = frame
        .stations
        .iter()
        .filter_map(|s| s.token.as_ref())
        .collect();
    let tokens_agree = both_tokens.len() == 2 && both_tokens[0] == both_tokens[1];
    let lit = frame.matched || tokens_agree;
    let match_line = if lit {
        let tok = both_tokens.first().map(|t| t.as_str()).unwrap_or("?");
        format!(
            "{}{}  [ MATCH ]  both stations independently teleported \"{}\"  {}",
            AEON_BOLD, AEON_GREEN, tok, AEON_RESET
        )
    } else {
        format!(
            "{}  [ ----- ]  awaiting independent lockstep ...{}",
            AEON_GHOST, AEON_RESET
        )
    };
    let match_plain = if lit {
        "  [ MATCH ]  both stations independently teleported"
    } else {
        "  [ ----- ]  awaiting independent lockstep ..."
    };
    let lead2 = width.saturating_sub(match_plain.len().min(width)) / 2;
    out.push_str(&format!("{}{}\x1b[K\n", " ".repeat(lead2), match_line));

    out.push_str(&draw_box_footer(width, AEON_CYAN));
    out
}

// =====================================================================
// SKYMESH FRAME SERVER (HTTP / SSE side-channel)
// ---------------------------------------------------------------------
// A minimal std-only HTTP server (std::net::TcpListener + manual request
// parse + response) that EXPOSES the monitor's current Skymesh frame so
// the web app reads the SAME frame the TUI renders -- one source of
// truth. The render loop publishes each tick's frame into a shared
// Arc<Mutex<SkymeshFrame>>; the server reads it. The server runs on a
// background thread and never blocks the TUI.
//
// No new HTTP crate dependency: we parse the request line manually and
// write raw HTTP/1.1 responses, mirroring the raw-HTTP idiom used across
// the fat-station bins (manual TcpListener::incoming + per-connection
// thread). Endpoints:
//   GET  /skymesh/frame.json -> current frame as JSON
//   GET  /skymesh/stream     -> SSE: `data: <frame json>\n\n` @ ~4 fps
//   GET  /healthz             -> "ok"
//   OPTIONS *                 -> 204 + CORS (preflight)
//
// All responses carry `Access-Control-Allow-Origin: *`.
// =====================================================================

/// Common CORS headers applied to every response (browser side-channel).
const SKYMESH_CORS: &str = concat!(
    "Access-Control-Allow-Origin: *\r\n",
    "Access-Control-Allow-Methods: GET, POST, OPTIONS\r\n",
    "Access-Control-Allow-Headers: *\r\n",
    "Cache-Control: no-store\r\n",
);

/// Snapshot the shared frame and serialize it. Falls back to a baked
/// fixture if the lock is somehow poisoned so the endpoint never 500s.
/// Retained as the reference pattern the generic `/monitor/` server mirrors;
/// the unified `monitor_handle_conn` now serves the `/skymesh/*` routes.
#[allow(dead_code)]
fn skymesh_shared_json(shared: &Arc<Mutex<SkymeshFrame>>) -> String {
    let frame = match shared.lock() {
        Ok(g) => g.clone(),
        Err(poisoned) => poisoned.into_inner().clone(),
    };
    serde_json::to_string(&frame).unwrap_or_else(|_| "{}".to_string())
}

/// Write a simple HTTP/1.1 response with the given status, content type
/// and body. Returns Err on a broken pipe (peer hung up).
fn skymesh_write_response(
    stream: &mut std::net::TcpStream,
    status_line: &str,
    content_type: &str,
    body: &[u8],
) -> io::Result<()> {
    let head = format!(
        "{status_line}\r\n{cors}Content-Type: {content_type}\r\nContent-Length: {len}\r\nConnection: close\r\n\r\n",
        cors = SKYMESH_CORS,
        len = body.len(),
    );
    stream.write_all(head.as_bytes())?;
    stream.write_all(body)?;
    stream.flush()
}

/// Handle one accepted connection: parse the request line, route, and
/// respond. `/skymesh/stream` keeps the connection open (SSE).
/// Retained as the reference pattern; `monitor_handle_conn` now serves these
/// routes from the unified listener.
#[allow(dead_code)]
fn skymesh_handle_conn(mut stream: std::net::TcpStream, shared: Arc<Mutex<SkymeshFrame>>) {
    // Read just enough to capture the request line + headers. We do not
    // need the body (all endpoints are GET/OPTIONS). A small bounded read
    // is sufficient for the request line.
    let mut buf = [0u8; 2048];
    let n = match stream.read(&mut buf) {
        Ok(0) => return,
        Ok(n) => n,
        Err(_) => return,
    };
    let req = String::from_utf8_lossy(&buf[..n]);
    let mut parts = req.split_whitespace();
    let method = parts.next().unwrap_or("");
    let raw_path = parts.next().unwrap_or("/");
    // Split path and query (e.g. /skymesh/frame.json?format=bw).
    let mut path_query = raw_path.splitn(2, '?');
    let path = path_query.next().unwrap_or("/");
    let query = path_query.next().unwrap_or("");
    // bitwise IPC variant: `?format=bw` returns a length-prefixed `.bw`
    // frame (u32 LE length + bw_codec blob) instead of plain JSON. The
    // browser path stays JSON; native-to-native consumers can opt in.
    let want_bw = query.split('&').any(|kv| kv == "format=bw");

    if method == "OPTIONS" {
        let head = format!(
            "HTTP/1.1 204 No Content\r\n{cors}Content-Length: 0\r\nConnection: close\r\n\r\n",
            cors = SKYMESH_CORS,
        );
        let _ = stream.write_all(head.as_bytes());
        let _ = stream.flush();
        return;
    }

    if method != "GET" {
        let _ = skymesh_write_response(
            &mut stream,
            "HTTP/1.1 405 Method Not Allowed",
            "text/plain; charset=utf-8",
            b"method not allowed",
        );
        return;
    }

    match path {
        "/healthz" => {
            let _ = skymesh_write_response(
                &mut stream,
                "HTTP/1.1 200 OK",
                "text/plain; charset=utf-8",
                b"ok",
            );
        }
        "/skymesh/frame.json" => {
            let json = skymesh_shared_json(&shared);
            if want_bw {
                // bitwise IPC: encode the JSON bytes through the canonical
                // bw_codec wire (same codec amplituhedron_wire frames BWAH
                // with), then length-prefix it (u32 LE) so a native reader
                // can frame it off a stream.
                let body =
                    match bitwise::bw_codec::encode_bw(json.as_bytes(), "application/json", None) {
                        Ok(bw) => {
                            let mut framed = Vec::with_capacity(bw.len() + 4);
                            framed.extend_from_slice(&(bw.len() as u32).to_le_bytes());
                            framed.extend_from_slice(&bw);
                            framed
                        }
                        Err(_) => json.into_bytes(),
                    };
                let _ = skymesh_write_response(
                    &mut stream,
                    "HTTP/1.1 200 OK",
                    "application/x-bitwise-frame",
                    &body,
                );
            } else {
                let _ = skymesh_write_response(
                    &mut stream,
                    "HTTP/1.1 200 OK",
                    "application/json; charset=utf-8",
                    json.as_bytes(),
                );
            }
        }
        "/skymesh/stream" => {
            // SSE: open-ended response. We write the header WITHOUT a
            // Content-Length, then push `data:` events forever (4 fps)
            // reflecting whatever frame the monitor is currently showing.
            let head = format!(
                "HTTP/1.1 200 OK\r\n{cors}Content-Type: text/event-stream\r\nConnection: keep-alive\r\n\r\n",
                cors = SKYMESH_CORS,
            );
            if stream.write_all(head.as_bytes()).is_err() {
                return;
            }
            let _ = stream.flush();
            loop {
                let json = skymesh_shared_json(&shared);
                let event = format!("data: {}\n\n", json);
                if stream.write_all(event.as_bytes()).is_err() {
                    break; // peer closed; drop the connection
                }
                if stream.flush().is_err() {
                    break;
                }
                std::thread::sleep(std::time::Duration::from_millis(250));
            }
        }
        _ => {
            let _ = skymesh_write_response(
                &mut stream,
                "HTTP/1.1 404 Not Found",
                "text/plain; charset=utf-8",
                b"not found",
            );
        }
    }
}

/// Spawn the Skymesh frame server on a background thread. Binds
/// 127.0.0.1:<port>; logs the bound address to stderr (visible before the
/// alt-screen takes over) and serves each connection on its own thread so
/// long-lived SSE streams never starve the others. Returns immediately;
/// the TUI keeps rendering. On bind failure we log and give up on the
/// side-channel without taking down the monitor.
/// Superseded by `spawn_monitor_server` (one listener, two routers); retained
/// as the reference implementation.
#[allow(dead_code)]
fn spawn_skymesh_server(port: u16, shared: Arc<Mutex<SkymeshFrame>>) {
    std::thread::spawn(move || {
        let addr = format!("127.0.0.1:{}", port);
        let listener = match std::net::TcpListener::bind(&addr) {
            Ok(l) => l,
            Err(e) => {
                eprintln!(
                    "[skymesh-serve] bind {} failed: {} (side-channel disabled)",
                    addr, e
                );
                return;
            }
        };
        eprintln!(
            "[skymesh-serve] http://{} -- GET /skymesh/frame.json | /skymesh/stream | /healthz",
            addr
        );
        for incoming in listener.incoming() {
            match incoming {
                Ok(stream) => {
                    let shared = Arc::clone(&shared);
                    std::thread::spawn(move || skymesh_handle_conn(stream, shared));
                }
                Err(e) => {
                    eprintln!("[skymesh-serve] accept error: {}", e);
                }
            }
        }
    });
}

/// Resolve the serve port from `--serve <port>` or the
/// `GNOSIS_AEON_MONITOR_SKYMESH_SERVE` env var. Returns `None` when the
/// side-channel is not requested (additive, opt-in). A bare `--serve`
/// with no/invalid argument falls back to the default port 8722.
fn skymesh_serve_port(args: &[String]) -> Option<u16> {
    let mut it = args.iter();
    while let Some(a) = it.next() {
        if a == "--serve" {
            return match it.next() {
                Some(p) => p.parse::<u16>().ok().or(Some(SKYMESH_DEFAULT_SERVE_PORT)),
                None => Some(SKYMESH_DEFAULT_SERVE_PORT),
            };
        }
    }
    std::env::var("GNOSIS_AEON_MONITOR_SKYMESH_SERVE")
        .ok()
        .map(|v| v.parse::<u16>().unwrap_or(SKYMESH_DEFAULT_SERVE_PORT))
}

// =====================================================================
// SKYMESH UDP PUBLISHER -- aeon Flow wire (NOT raw JSON)
// ---------------------------------------------------------------------
// In the `--serve --udp` path each rendered frame is also emitted as
// exactly ONE FlowCodec-encoded ConsciousTick datagram on the Skymesh
// Flow stream (0x5353). The 10-byte big-endian header + JSON payload is
// the canonical aeon Flow protocol -- the same bytes the TypeScript
// publisher (rtlsdr-mock-sim/skymesh-serve.mts) and aeon-flux speak.
//
// Wire authority: open-source/aeon/src/flow/FlowCodec.ts
//   [0..1] stream_id u16 BE   (0x5353)
//   [2..5] sequence  u32 BE   (monotonic 0,1,2,...)
//   [6]    flags     u8       (FORK|FOLD = 0x05)
//   [7..9] length    u24 BE   (payload byte length)
//   [10..] payload   utf8(JSON of the gnosis.skymesh.v1 frame)
// =====================================================================

/// FIXED Flow wire contract (other agents depend on these exact values).
const SKYMESH_FLOW_STREAM_ID: u16 = 0x5353;
/// Flow flags FORK (0x01) | FOLD (0x04) = 0x05 for a Skymesh broadcast tick.
const SKYMESH_FLOW_FLAGS: u8 = 0x05;
/// Default multicast group + port + TTL for the broadcast hose.
const SKYMESH_UDP_DEFAULT_PORT: u16 = 8725;
const SKYMESH_UDP_DEFAULT_GROUP: &str = "239.69.0.66";
const SKYMESH_UDP_DEFAULT_TTL: u32 = 1;
/// Max UDP/IPv4 payload (65535 - 20 IP header - 8 UDP header). A Flow frame
/// whose encoded bytes exceed this is skipped + warned, never truncated.
const SKYMESH_UDP_MAX_DATAGRAM_BYTES: usize = 65507;

/// UDP publisher configuration parsed from `--udp [port] / --udp-group /
/// --udp-ttl / --udp-target host:port`. `None` when `--udp` is absent.
struct SkymeshUdpConfig {
    port: u16,
    group: String,
    ttl: u32,
    targets: Vec<(String, u16)>,
}

/// Parse a `host:port` unicast target (splits on the LAST colon to allow
/// IPv6-ish hosts). Returns `None` on a malformed entry (logged by the caller).
fn parse_udp_target(raw: &str) -> Option<(String, u16)> {
    let idx = raw.rfind(':')?;
    if idx == 0 || idx == raw.len() - 1 {
        return None;
    }
    let host = raw[..idx].to_string();
    let port: u16 = raw[idx + 1..].parse().ok()?;
    if port == 0 {
        return None;
    }
    Some((host, port))
}

/// Resolve the UDP publisher config from args. `--udp` may carry an optional
/// port (`--udp 8725`); a bare `--udp` (or one followed by another flag) uses
/// the default. Returns `None` when `--udp` is not present (opt-in side-channel).
fn skymesh_udp_config(args: &[String]) -> Option<SkymeshUdpConfig> {
    let udp_idx = args.iter().position(|a| a == "--udp")?;
    let port = match args.get(udp_idx + 1) {
        Some(next) if !next.starts_with("--") => {
            next.parse::<u16>().unwrap_or(SKYMESH_UDP_DEFAULT_PORT)
        }
        _ => SKYMESH_UDP_DEFAULT_PORT,
    };

    let mut group = SKYMESH_UDP_DEFAULT_GROUP.to_string();
    let mut ttl = SKYMESH_UDP_DEFAULT_TTL;
    let mut targets: Vec<(String, u16)> = Vec::new();

    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--udp-group" => {
                if let Some(g) = args.get(i + 1) {
                    group = g.clone();
                    i += 1;
                }
            }
            "--udp-ttl" => {
                if let Some(t) = args.get(i + 1) {
                    if let Ok(v) = t.parse::<u32>() {
                        ttl = v;
                    }
                    i += 1;
                }
            }
            "--udp-target" => {
                if let Some(t) = args.get(i + 1) {
                    match parse_udp_target(t) {
                        Some(target) => targets.push(target),
                        None => eprintln!(
                            "[skymesh-serve] udp: ignoring malformed --udp-target '{}' (want host:port)",
                            t
                        ),
                    }
                    i += 1;
                }
            }
            _ => {}
        }
        i += 1;
    }

    Some(SkymeshUdpConfig {
        port,
        group,
        ttl,
        targets,
    })
}

/// Build one FlowCodec datagram: 10-byte big-endian header + the JSON payload.
/// `payload` is the utf8 JSON of the gnosis.skymesh.v1 frame.
/// @see open-source/aeon/src/flow/FlowCodec.ts (the wire authority).
fn encode_skymesh_flow_frame(sequence: u32, payload: &[u8]) -> Vec<u8> {
    let len = payload.len();
    let mut buf = Vec::with_capacity(10 + len);
    // stream_id u16 BE
    buf.extend_from_slice(&SKYMESH_FLOW_STREAM_ID.to_be_bytes());
    // sequence u32 BE
    buf.extend_from_slice(&sequence.to_be_bytes());
    // flags u8
    buf.push(SKYMESH_FLOW_FLAGS);
    // length u24 BE
    buf.push(((len >> 16) & 0xff) as u8);
    buf.push(((len >> 8) & 0xff) as u8);
    buf.push((len & 0xff) as u8);
    // payload
    buf.extend_from_slice(payload);
    buf
}

/// A best-effort UDP Flow publisher. Created once; send one Flow datagram per
/// frame. Never fatal: socket/send failures are logged and swallowed so the
/// TUI + HTTP/SSE keep running.
struct SkymeshUdpPublisher {
    socket: std::net::UdpSocket,
    group: String,
    port: u16,
    targets: Vec<(String, u16)>,
    sequence: u32,
}

impl SkymeshUdpPublisher {
    /// Bind a udp4 socket and set the multicast TTL. Returns `None` on any
    /// setup failure (the caller treats UDP as opt-in best-effort).
    fn new(cfg: &SkymeshUdpConfig) -> Option<Self> {
        let socket = match std::net::UdpSocket::bind("0.0.0.0:0") {
            Ok(s) => s,
            Err(e) => {
                eprintln!(
                    "[skymesh-serve] udp: bind failed: {} (udp disabled, http/sse unaffected)",
                    e
                );
                return None;
            }
        };
        if let Err(e) = socket.set_multicast_ttl_v4(cfg.ttl) {
            eprintln!(
                "[skymesh-serve] udp: set_multicast_ttl_v4 failed: {} (multicast sends may be skipped; unicast still used)",
                e
            );
        }
        Some(Self {
            socket,
            group: cfg.group.clone(),
            port: cfg.port,
            targets: cfg.targets.clone(),
            sequence: 0,
        })
    }

    /// Encode the JSON as one Flow datagram and send it to the multicast group
    /// plus every unicast target. Advances the monotonic sequence counter.
    fn publish(&mut self, json: &str) {
        let datagram = encode_skymesh_flow_frame(self.sequence, json.as_bytes());
        self.sequence = self.sequence.wrapping_add(1);

        // Honest size guard on the FULL Flow datagram: never truncate.
        if datagram.len() > SKYMESH_UDP_MAX_DATAGRAM_BYTES {
            eprintln!(
                "[skymesh-serve] udp: Flow frame is {} bytes (> {} UDP/IPv4 limit); skipping this datagram (never truncated). HTTP/SSE unaffected.",
                datagram.len(),
                SKYMESH_UDP_MAX_DATAGRAM_BYTES
            );
            return;
        }

        // Multicast fan-out (the skymesh broadcast).
        let group_addr = format!("{}:{}", self.group, self.port);
        if let Err(e) = self.socket.send_to(&datagram, &group_addr) {
            eprintln!(
                "[skymesh-serve] udp: send to {} failed: {} (continuing)",
                group_addr, e
            );
        }
        // Unicast targets.
        for (host, port) in &self.targets {
            let addr = format!("{}:{}", host, port);
            if let Err(e) = self.socket.send_to(&datagram, &addr) {
                eprintln!(
                    "[skymesh-serve] udp: send to {} failed: {} (continuing)",
                    addr, e
                );
            }
        }
    }
}

// =====================================================================
// GENERIC /monitor/ SERVE PIPELINE -- gnosis.monitor.v1
// ---------------------------------------------------------------------
// A single envelope shape (`gnosis.monitor.v1`) that subsumes every scene
// aeon-monitor / aeon-tui can render: raster grids (waterfall, NOAA APT,
// PNG images), structured vector payloads (handshake cloud, residual
// ladder, gate telemetry, self-talk), the existing Skymesh teleport frame
// (carried verbatim under `vector`), and same-origin HTML embeds (knot-viz).
//
// The HTTP/SSE server mirrors `skymesh_handle_conn` exactly (raw std-only
// TcpListener + per-connection thread). The SAME listener routes both the
// legacy `/skymesh/*` endpoints (back-compat) and the new `/monitor/*`
// endpoints, so there is only ONE bind.
//
// Wire authority for the envelope: docs/MONITOR_CLIENT_DESIGN.md (section 1)
// and open-source/aeon/src/flow/MonitorFlow.ts (the TS mirror).
// =====================================================================

/// Schema discriminant for the generic monitor envelope. The renderer
/// rejects any other value (mirrors SKYMESH_FRAME_SCHEMA).
const MONITOR_FRAME_SCHEMA: &str = "gnosis.monitor.v1";

/// One `gnosis.monitor.v1` envelope. camelCase on the wire to match the
/// existing Skymesh contract (apps/skymesh/client/lib/contract.ts).
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
struct MonitorEnvelope {
    /// Discriminant; renderer rejects others.
    schema_version: String,
    /// Scene id (matches the /monitor/scenes catalog).
    scene: String,
    /// Coarse renderer dispatch: "raster" | "vector" | "embed" | "skymesh".
    kind: String,
    /// Human label for nav + header.
    title: String,
    /// Raster columns (cells for vector).
    width: u32,
    /// Raster rows.
    height: u32,
    /// 1 = grayscale, 4 = RGBA. raster only.
    #[serde(skip_serializing_if = "Option::is_none")]
    channels: Option<u8>,
    /// Raster only: base64 of exactly width*height*channels bytes, row-major.
    #[serde(skip_serializing_if = "Option::is_none")]
    raster: Option<String>,
    /// Raster only, optional: named palette for grayscale colorization.
    #[serde(skip_serializing_if = "Option::is_none")]
    palette: Option<String>,
    /// vector/skymesh only: structured payload (scene-typed).
    #[serde(skip_serializing_if = "Option::is_none")]
    vector: Option<serde_json::Value>,
    /// embed only: { url, params }.
    #[serde(skip_serializing_if = "Option::is_none")]
    embed: Option<MonitorEmbed>,
    /// Flat string->string passthrough (PleromaticFrame.attributes).
    attributes: HashMap<String, String>,
    /// Scene-agnostic provenance + numbers.
    metadata: serde_json::Value,
    /// UNIX ms (PleromaticFrame.timestamp_ms).
    ts: u64,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct MonitorEmbed {
    url: String,
    #[serde(default, skip_serializing_if = "serde_json::Value::is_null")]
    params: serde_json::Value,
}

